window.__QUIZ_SUBJECT__=[{"id": "objective>Office Practice>2019>1", "subject": "Office Practice", "year": "2019", "type": "Objective", "topic": "FILING : STEPS IN FILING", "question": "Miscellaneous file should be opened when", "images": [], "options": {"A": "the original file form document cannot be located", "B": "there is insufficient correspondence from one source to justify opening new file.", "C": "there is insufficient time for the filing clerk to assemble relevant document to open a new file", "D": "there are sufficient documents from various sources to justify opening a new file"}, "answer": "B", "explanation": "A miscellaneous file is typically opened when there is not enough correspondence from one source to justify opening a new file. This is because a miscellaneous file is a general file that can contain various documents from different sources. It is not used when the original document cannot be located, when there is insufficient time for the filing clerk to assemble relevant documents, or when there are sufficient documents from various sources to justify opening a new file.", "marks": "1", "difficulty": "2"}, {"id": "objective>Office Practice>2019>2", "subject": "Office Practice", "year": "2019", "type": "Objective", "topic": "COMMUNICATION : TYPES", "question": "Transmission of information between officers of the same level is", "images": [], "options": {"A": "diagonal communication", "B": "vertical communication", "C": "horizontal communication", "D": "lateral communication"}, "answer": "C", "explanation": "The transmission of information between officers of the same level is referred to as horizontal communication. This is because it occurs between individuals who are on the same level of the organizational hierarchy. It is not referred to as diagonal, vertical, or lateral communication. Diagonal communication occurs between different departments and levels, vertical communication occurs between different levels of the organizational hierarchy, and lateral communication is another term for horizontal communication.", "marks": "1", "difficulty": "2"}, {"id": "objective>Office Practice>2019>3", "subject": "Office Practice", "year": "2019", "type": "Objective", "topic": "INFORMATION : SOURCES", "question": "\"Who is who\" is a book that contains information of", "images": [], "options": {"A": "important people who are still living.", "B": "people who are dead.", "C": "people who are not eminent.", "D": "late people but important."}, "answer": "A", "explanation": "\"Who is who\" is a book that contains information about important people who are still living. It does not contain information about people who are dead, people who are not eminent, or late people but important. The purpose of this book is to provide information about individuals who have achieved significant accomplishments in their respective fields and are still alive.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2019>4", "subject": "Office Practice", "year": "2019", "type": "Objective", "topic": "THE RECEPTION : DOCUMENTS HANDLED BY A RECEPTIONIST", "question": "Which of the following documents is handled by the receptionist?", "images": [], "options": {"A": "Minutes of meetings", "B": "Telephone message pad", "C": "The manager's diary", "D": "Requisition form"}, "answer": "B", "explanation": "A receptionist is often responsible for handling a telephone message pad. This is because they are usually the first point of contact for anyone calling the office. They take messages when the person being called is not available and note them down on the telephone message pad. The other options are not typically handled by the receptionist. Minutes of meetings are usually handled by the secretary, the manager's diary is handled by the manager or their assistant, and a requisition form is typically handled by the procurement department.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2019>5", "subject": "Office Practice", "year": "2019", "type": "Objective", "topic": "MAILS : PROCEDURES FOR HANDLING INCOMING AND OUTGOING MAILS", "question": "The type of incoming mail that should be delivered to their addresses unopened is", "images": [], "options": {"A": "urgent mail", "B": "personal mail", "C": "official mail", "D": "registered mail"}, "answer": "B", "explanation": "Personal mail should be delivered to their addresses unopened. This is because personal mail is private and confidential. Opening someone else's personal mail is a breach of privacy. The other types of mail, such as urgent, official, and registered mail, may need to be opened by office staff to process them.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2019>6", "subject": "Office Practice", "year": "2019", "type": "Objective", "topic": "FILING : SYSTEMS OF FILING", "question": "Filing document according to dates is", "images": [], "options": {"A": "geographical filing", "B": "subject filing", "C": "numerical filing", "D": "chronological filing"}, "answer": "D", "explanation": "Filing documents according to dates is known as chronological filing. The term 'chronological' comes from the Greek words 'chronos' (time) and 'logos' (study), which means it's a method that involves arranging events in the order of their occurrence in time. Therefore, when documents are filed according to their dates, it's called chronological filing. The other options, geographical, subject, and numerical filing, involve arranging files based on location, subject matter, and numbers respectively.", "marks": "1", "difficulty": "2"}, {"id": "objective>Office Practice>2019>7", "subject": "Office Practice", "year": "2019", "type": "Objective", "topic": "REPORT WRITINGS : PARTS OF A REPORT", "question": "The three components of a short report are the", "images": [], "options": {"A": "introduction, body and findings.", "B": "introduction, body and conclusion.", "C": "terms of reference, body and conclusion.", "D": "terms of reference, body and recommendations"}, "answer": "B", "explanation": "A short report typically consists of three main components: the introduction, the body, and the conclusion. The introduction sets the context and outlines the purpose of the report. The body contains the main content and findings of the report. The conclusion summarizes the report and may include recommendations or next steps.", "marks": "1", "difficulty": "2"}, {"id": "objective>Office Practice>2019>8", "subject": "Office Practice", "year": "2019", "type": "Objective", "topic": "COMMUNICATION : METHODS/MEDIA OF COMMUNICATION", "question": "The communication channel in the diagram below is", "images": ["Office Practice/imgs/2019/ssce2019officepq8.png"], "options": {"A": "vertical.", "B": "diagonal.", "C": "lateral.", "D": "horizontal."}, "answer": "C", "explanation": "The communication channel in the diagraom below is lateral communication channel  &nbsp &nbsp &nbsp&nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp General manager  &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp ↓  &nbsp &nbsp &nbsp&nbsp &nbsp&nbsp &nbsp ↓  Personal manager &nbsp marketing manager", "marks": "1", "difficulty": "2"}, {"id": "objective>Office Practice>2019>9", "subject": "Office Practice", "year": "2019", "type": "Objective", "topic": "MEETINGS : TYPES", "question": "A committee which ceases to exist after completing its assignment is", "images": [], "options": {"A": "a standing committee", "B": "an investigatory committee", "C": "ad-hoc committee", "D": "advisory committee"}, "answer": "C", "explanation": "An ad-hoc committee is a type of committee that is formed for a specific task or objective, and is dissolved after the completion of the task or achievement of the objective. The term 'ad-hoc' is a Latin phrase that literally means 'for this', implying a solution designed for a specific problem or task.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2019>10", "subject": "Office Practice", "year": "2019", "type": "Objective", "topic": "OFFICE DOCUMENTS : MEANING OF OFFICE DOCUMENT", "question": "Which of the following statements is true about a quotation? It shows the", "images": [], "options": {"A": "total of goods supplied.", "B": "quality of goods in the warehouse.", "C": "total cost of goods produced.", "D": "prices of goods enquired about."}, "answer": "D", "explanation": "A quotation in business context is a document that a supplier submits to a potential customer offering to sell goods or services at a certain price. It shows the prices of goods enquired about, not the total of goods supplied, the quality of goods in the warehouse, or the total cost of goods produced.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2019>11", "subject": "Office Practice", "year": "2019", "type": "Objective", "topic": "MEETINGS : ROLES OF THE CHAIRMAN/SECRETARY", "question": "To break a tie resulting from a poll, the chairman should", "images": [], "options": {"A": "ask members to vote again", "B": "use his power of casting vote", "C": "use his discretion to take a decision", "D": "ask his executive members to advise him"}, "answer": "B", "explanation": "In a formal meeting, if a vote results in a tie, the chairman has the power to cast a deciding vote. This is known as the chairman's casting vote. It is used to break the tie and make a decision. Therefore, the chairman should use his power of casting vote.", "marks": "1", "difficulty": "2"}, {"id": "objective>Office Practice>2019>12", "subject": "Office Practice", "year": "2019", "type": "Objective", "topic": "DEPARTMENTS IN AN ORGANIZATION : FUNCTIONS OF EACH DEPARTMENT", "question": "The raw materials and equipment needed in an organization should be bought by the", "images": [], "options": {"A": "human resource department", "B": "purchasing department", "C": "marketing department", "D": "accounts department"}, "answer": "B", "explanation": "The purchasing department in an organization is responsible for acquiring the necessary raw materials and equipment. They negotiate with suppliers, place orders, and ensure that the required materials are available when needed. Therefore, the raw materials and equipment needed in an organization should be bought by the purchasing department.", "marks": "1", "difficulty": "2"}, {"id": "objective>Office Practice>2019>13", "subject": "Office Practice", "year": "2019", "type": "Objective", "topic": "MAILS : TYPES OF MAILS", "question": "A letter sent by Mrs. Benson to her husband by post through his office address is an example of", "images": [], "options": {"A": "urgent mail.", "B": "official mail.", "C": "personal mail.", "D": "confidential mail."}, "answer": "C", "explanation": "A letter sent by Mrs. Benson to her husband through his office address is a personal mail. Personal mail refers to any correspondence sent to an individual in a personal capacity, rather than as a representative of a business or organization. Even though it was sent to his office address, the content of the mail is likely personal since it's from his wife.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2019>14", "subject": "Office Practice", "year": "2019", "type": "Objective", "topic": "COMMUNICATION : METHODS/MEDIA OF COMMUNICATION", "question": "In order to eliminate barrier to effective communication, the sender should", "images": [], "options": {"A": "use as much jargons as he can.", "B": "consider the level of recipient's education.", "C": "expect the recipient to use a dictionary in decoding.", "D": "discourage the recipient from giving a feedback."}, "answer": "B", "explanation": "Effective communication requires the sender to consider the level of the recipient's education. This is because the understanding of the message being communicated depends on the recipient's level of education. Using jargons or expecting the recipient to use a dictionary in decoding may lead to misunderstanding or misinterpretation of the message. Feedback is also an important part of communication as it helps the sender to know if the message was understood or not.", "marks": "1", "difficulty": "2"}, {"id": "objective>Office Practice>2019>15", "subject": "Office Practice", "year": "2019", "type": "Objective", "topic": "OFFICE EQUIPMENT : TYPES OF OFFICE EQUIPMENT", "question": "The machine that is used to destroy unwanted papers into unreadable pieces is", "images": [], "options": {"A": "franking machine.", "B": "guillotine machine.", "C": "perforating machine.", "D": "shredding machine."}, "answer": "D", "explanation": "A shredding machine is used to destroy unwanted papers into unreadable pieces. This is done for security reasons to prevent unauthorized access to sensitive information. A franking machine is used to print postage stamps and a guillotine machine is used to cut large sheets of paper. A perforating machine is used to make holes in paper.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2019>16", "subject": "Office Practice", "year": "2019", "type": "Objective", "topic": "DEPARTMENTS IN AN ORGANIZATION : ORGANIZATIONAL CHART", "question": "A diagram that shows the line of responsibilities and authorities in a company is", "images": [], "options": {"A": "pie chart.", "B": "bar chart.", "C": "pictorial chart.", "D": "organizational chart."}, "answer": "D", "explanation": "An organizational chart is a diagram that shows the line of responsibilities and authorities in a company. It shows the structure of the organization and the relationship between the different parts. A pie chart is used to show proportions of a whole, a bar chart is used to compare different groups and a pictorial chart uses images to represent data.", "marks": "1", "difficulty": "2"}, {"id": "objective>Office Practice>2019>17", "subject": "Office Practice", "year": "2019", "type": "Objective", "topic": "MEETINGS : TYPES", "question": "A meeting conducted yearly by companies is", "images": [], "options": {"A": "extra ordinary meeting", "B": "staff meeting", "C": "annual general meeting", "D": "board meeting"}, "answer": "C", "explanation": "An Annual General Meeting (AGM) is a meeting that is conducted yearly by companies. It is a mandatory yearly gathering of a company's interested shareholders. At an AGM, the directors of the company present an annual report containing information for shareholders about the company's performance and strategy. Shareholders with voting rights vote on current issues, such as appointments to the company's board of directors, executive compensation, dividend payments and selection of auditors.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2019>18", "subject": "Office Practice", "year": "2019", "type": "Objective", "topic": "DEPARTMENTS IN AN ORGANIZATION : FUNCTIONS OF EACH DEPARTMENT", "question": "The department that is responsible for replenishing stock in an organization is the", "images": [], "options": {"A": "purchasing department", "B": "administrative department", "C": "production department", "D": "sales department"}, "answer": "A", "explanation": "The Purchasing Department is responsible for procuring all the goods, services, and equipment necessary to operate the business. This includes replenishing stock in an organization. Their role is to ensure the goods and services are of the right quality, at the right price, from the right source, at the right specification that meets the user needs, and are delivered at the right time.", "marks": "1", "difficulty": "2"}, {"id": "objective>Office Practice>2019>19", "subject": "Office Practice", "year": "2019", "type": "Objective", "topic": "FILING : SYSTEMS OF FILING", "question": "An advantage of central filing is that it ensures", "images": [], "options": {"A": "easy retrieval of files.", "B": "easy access to files.", "C": "high level of confidentiality.", "D": "uniformity of filing system."}, "answer": "D", "explanation": "Central filing is a system where all the files of an organization are kept in one place or department. The advantage of this system is that it ensures uniformity of the filing system. This means that all files are arranged in a consistent manner, making it easier to locate and retrieve files when needed. It also helps in maintaining consistency in the filing procedures and policies of the organization.", "marks": "1", "difficulty": "2"}, {"id": "objective>Office Practice>2019>20", "subject": "Office Practice", "year": "2019", "type": "Objective", "topic": "MAILS : CLASSIFICATION OF MAILS", "question": "Mails requiring prompt attention are", "images": [], "options": {"A": "registered mails.", "B": "personal mails.", "C": "urgent mails.", "D": "confidential mails"}, "answer": "C", "explanation": "Urgent mails are those that require immediate attention, hence they are the mails that require prompt attention.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2019>21", "subject": "Office Practice", "year": "2019", "type": "Objective", "topic": "FILING : FILING EQUIPMENT", "question": "Which of the following equipment is used for electronic filing?", "images": [], "options": {"A": "Printer", "B": "Fax machine", "C": "Computer", "D": "Drawer"}, "answer": "C", "explanation": "Electronic filing involves the use of digital systems to store and manage files, and this is typically done on a computer.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2019>22", "subject": "Office Practice", "year": "2019", "type": "Objective", "topic": "OFFICE CORRESPONDENCE : MEANING OF OFFICE CORRESPONDENCE", "question": "The correspondence conveying the same information to different organization is/are", "images": [], "options": {"A": "business letter", "B": "memorandum", "C": "minutes", "D": "circulars"}, "answer": "D", "explanation": "Circulars are a type of communication that is sent to a large number of people, typically within an organization, but it can also be sent to multiple organizations, hence they are the correspondence that conveys the same information to different organizations.", "marks": "1", "difficulty": "2"}, {"id": "objective>Office Practice>2019>23", "subject": "Office Practice", "year": "2019", "type": "Objective", "topic": "MEETINGS : MEETING TERMINOLOGIES", "question": "The list of items to be discussed in a meeting is", "images": [], "options": {"A": "amendment", "B": "agenda", "C": "resolution", "D": "motion"}, "answer": "B", "explanation": "The list of items to be discussed in a meeting is referred to as the 'agenda'. An agenda is a list of activities in the order in which they are to be taken up, beginning with the call to order and ending with adjournment. It usually includes one or more specific items of business to be acted upon.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2019>24", "subject": "Office Practice", "year": "2019", "type": "Objective", "topic": "OFFICE EQUIPMENT : TYPES OF OFFICE EQUIPMENT", "question": "Which of the following factors will be considered before buying office furniture?", "images": [], "options": {"A": "The colour of the furniture", "B": "The size of the furniture", "C": "The weight of the furniture", "D": "The source of the furniture"}, "answer": "B", "explanation": "Before buying office furniture, one of the key factors to consider is the size of the furniture. This is because the furniture should fit well in the available office space and also accommodate the employees comfortably. The other options such as colour, weight and source of the furniture are secondary considerations.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2019>25", "subject": "Office Practice", "year": "2019", "type": "Objective", "topic": "THE OFFICE : PRINCIPLES OF OFFICE", "question": "The principles of organization which states that a worker should not take orders from more than one superior officer is", "images": [], "options": {"A": "unity of objective", "B": "chain of command", "C": "span of control", "D": "unity of purpose"}, "answer": "C", "explanation": "The principle of organization which states that a worker should not take orders from more than one superior officer is known as 'unity of command'. Unity of command is a principle in which an employee reports to only one manager. This helps to prevent confusion, conflicts, and misunderstanding in the organization.", "marks": "1", "difficulty": "2"}, {"id": "objective>Office Practice>2019>26", "subject": "Office Practice", "year": "2019", "type": "Objective", "topic": "THE RECEPTION : DUTIES", "question": "One of the ways a receptionist show pleasantries to visitors is by", "images": [], "options": {"A": "standing up to greet them", "B": "welcoming all visitors with a smile", "C": "welcoming them with a big hug", "D": "asking about their families"}, "answer": "B", "explanation": "A receptionist shows pleasantries to visitors by welcoming them with a smile. This is a professional and friendly way to greet visitors that makes them feel welcomed and comfortable. Standing up to greet them is also a way to show respect, but it is not as universally applicable as a smile. Welcoming them with a big hug or asking about their families can be seen as too personal or unprofessional in many contexts.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2019>27", "subject": "Office Practice", "year": "2019", "type": "Objective", "topic": "THE OFFICE : LAYOUT OF AN OFFICE", "question": "One of the advantages of a close office layout is that it", "images": [], "options": {"A": "enhances the prestige of the user.", "B": "ensures free flow of work.", "C": "makes supervision of workers easier.", "D": "enables common use of office equipment."}, "answer": "C", "explanation": "A closed office layout has the advantage of making supervision of workers easier. This is because in a closed office layout, each employee has their own separate space, which can be easily monitored by a supervisor. Enhancing the prestige of the user and ensuring free flow of work are not necessarily advantages of a closed office layout. Common use of office equipment is usually more associated with an open office layout.", "marks": "1", "difficulty": "2"}, {"id": "objective>Office Practice>2019>28", "subject": "Office Practice", "year": "2019", "type": "Objective", "topic": "MAILS : PROCEDURES FOR HANDLING INCOMING AND OUTGOING MAILS", "question": "Particulars of letters sent out from an office are entered in the", "images": [], "options": {"A": "dispatch book.", "B": "postage book.", "C": "remittance book.", "D": "office diary"}, "answer": "A", "explanation": "Particulars of letters sent out from an office are entered in the dispatch book. This is a record of all outgoing mail, including the recipient, date sent, and other relevant details. A postage book is used to keep track of postage costs, a remittance book is used for recording payments received, and an office diary is used for scheduling and noting down appointments and meetings.", "marks": "1", "difficulty": "2"}, {"id": "objective>Office Practice>2019>29", "subject": "Office Practice", "year": "2019", "type": "Objective", "topic": "MEETINGS : PURPOSE", "question": "A requirement of a valid meeting is that", "images": [], "options": {"A": "some proxies should be in attendance.", "B": "there should be a quorum.", "C": "all members should be in attendance.", "D": "items of its agenda should be completed."}, "answer": "B", "explanation": "A quorum is the minimum number of members of an assembly or society that must be present at any of its meetings to make the proceedings of that meeting valid. Therefore, for a meeting to be valid, there should be a quorum.", "marks": "1", "difficulty": "2"}, {"id": "objective>Office Practice>2019>30", "subject": "Office Practice", "year": "2019", "type": "Objective", "topic": "FILING : SYSTEMS OF FILING", "question": "A filing system where records are kept by various section within an organization is", "images": [], "options": {"A": "centralized filing system.", "B": "geographical filing system.", "C": "numerical filing system.", "D": "departmental filing system."}, "answer": "D", "explanation": "A departmental filing system is a system where records are kept by various sections within an organization. Each department or section maintains its own files. This system is beneficial in large organizations where departments are located far apart.", "marks": "1", "difficulty": "2"}, {"id": "objective>Office Practice>2019>31", "subject": "Office Practice", "year": "2019", "type": "Objective", "topic": "OFFICE EQUIPMENT : MEANING OF OFFICE EQUIPMENT", "question": "The term office equipment refers to", "images": [], "options": {"A": "machine and furniture.", "B": "wires and cables.", "C": "furniture and fittings.", "D": "machines and products."}, "answer": "A", "explanation": "Office equipment refers to the assets used by a company to conduct its business activities. This includes both machines (like computers, printers, fax machines) and furniture (like desks, chairs, cabinets) used in the office.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2019>32", "subject": "Office Practice", "year": "2019", "type": "Objective", "topic": "OFFICE DOCUMENTS : TYPES", "question": "Which of the following document is not used for business transaction?", "images": [], "options": {"A": "Price list", "B": "Quotation", "C": "Circular", "D": "Invoice"}, "answer": "C", "explanation": "A circular is not used for business transactions. It is a letter or advertisement that is sent to a large number of people at the same time. On the other hand, a price list, quotation, and invoice are all documents used in business transactions. A price list is a document that lists the prices of items or services. A quotation is a document that states the estimated cost for a particular job or service. An invoice is a document that lists goods that have been supplied or services that have been done and says how much money you owe for them.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2019>33", "subject": "Office Practice", "year": "2019", "type": "Objective", "topic": "REPORT WRITINGS : PARTS OF A REPORT", "question": "The opinion of an investigatory committee on its findings is stated in the report as", "images": [], "options": {"A": "introduction", "B": "terms of reference", "C": "conclusion", "D": "recommendation"}, "answer": "C", "explanation": "The opinion of an investigatory committee on its findings is stated in the report as the conclusion. The conclusion is the part of the report where the committee summarizes its findings and gives its opinion based on those findings. The introduction is where the committee introduces the subject of the investigation. The terms of reference are the guidelines that the committee follows during the investigation. The recommendation is where the committee suggests actions based on its findings.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2019>34", "subject": "Office Practice", "year": "2019", "type": "Objective", "topic": "FILING : SYSTEMS OF FILING", "question": "One of the disadvantages of numerical system of filing is that", "images": [], "options": {"A": "document retrieval takes longer time", "B": "there may be congestion in a file", "C": "there is difficulty of classification", "D": "there is difficulty of document retrieval where date is unknown"}, "answer": "A", "explanation": "One of the disadvantages of the numerical system of filing is that document retrieval takes longer time. In a numerical filing system, files are arranged in order of their assigned numbers. While this system is efficient for storing files, it can be time-consuming to retrieve a specific file because you have to go through the files in numerical order until you find the one you're looking for. The other options are not disadvantages of the numerical filing system.", "marks": "1", "difficulty": "2"}, {"id": "objective>Office Practice>2019>35", "subject": "Office Practice", "year": "2019", "type": "Objective", "topic": "COMMUNICATION : DEFINITION OF COMMUNICATION", "question": "The abbreviation \"ref\" on the letterhead of an organization represents", "images": [], "options": {"A": "refferer", "B": "referee", "C": "reference", "D": "referendum"}, "answer": "C", "explanation": "In the context of a letterhead, 'ref' stands for 'reference'. This is typically used to indicate a reference number or code that relates to a specific document or correspondence.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2019>36", "subject": "Office Practice", "year": "2019", "type": "Objective", "topic": "FILING : CLASSIFICATION OF FILING", "question": "A filing classification in which documents are stored according to their title is", "images": [], "options": {"A": "numerical filing", "B": "alpha-numerical filing", "C": "geographical filing", "D": "subject filing"}, "answer": "D", "explanation": "Subject filing is a method of classification where documents are stored according to their title or subject matter. This is different from numerical (based on numbers), alpha-numerical (based on a combination of numbers and letters), and geographical (based on location) filing.", "marks": "1", "difficulty": "2"}, {"id": "objective>Office Practice>2019>37", "subject": "Office Practice", "year": "2019", "type": "Objective", "topic": "INFORMATION : DEFINITIONS", "question": "A good information should be", "images": [], "options": {"A": "relevant", "B": "voluminous", "C": "costly", "D": "archived"}, "answer": "A", "explanation": "Good information should be relevant. This means it should be directly related to the matter at hand and useful for decision making. While it's important for information to be comprehensive, it doesn't necessarily have to be voluminous. Costly information or archived information doesn't inherently make it good.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2019>38", "subject": "Office Practice", "year": "2019", "type": "Objective", "topic": "THE OFFICE : LAYOUT OF AN OFFICE", "question": "Economy in the use of office equipment is one of the advantages of", "images": [], "options": {"A": "panoramic office.", "B": "closed office.", "C": "departmental office.", "D": "open office."}, "answer": "D", "explanation": "Open office is the correct answer because it is a type of office layout where workspaces are created in a large, open space without any barriers such as cubicles or walls. This layout is known to be economical as it allows for the efficient use of office equipment. It reduces the need for multiple equipment as resources can be shared among employees.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2019>39", "subject": "Office Practice", "year": "2019", "type": "Objective", "topic": "MEETINGS : TYPES", "question": "Formal meeting held by the directors of an organization to consider policy issues is", "images": [], "options": {"A": "statutory meeting", "B": "general meeting", "C": "board meeting", "D": "committee meeting"}, "answer": "C", "explanation": "A board meeting is a formal meeting held by the directors of an organization to consider policy issues. It is during these meetings that major decisions are made, and policies are formulated. A statutory meeting is the first meeting after the incorporation of a company, a general meeting is a gathering of the general membership of an organization, and a committee meeting is a gathering of a defined subset of an organization.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2019>40", "subject": "Office Practice", "year": "2019", "type": "Objective", "topic": "OFFICE CORRESPONDENCE : TYPES", "question": "Which of the following types of correspondence is used to convey information to a large number of customers?", "images": [], "options": {"A": "Bulleting", "B": "Memorandum", "C": "Circular letters", "D": "Personal letters"}, "answer": "C", "explanation": "Circular letters are used to convey information to a large number of customers. They are typically used by businesses when they need to send the same information to a large group of people, such as customers or employees. Bulletins are typically used for internal communication, memorandums are used for internal communication within an organization, and personal letters are used for individual communication.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2019>41", "subject": "Office Practice", "year": "2019", "type": "Objective", "topic": "REPORT WRITINGS : PARTS OF A REPORT", "question": "The part of a report where the highlights of an investigatory committee's assignment are stated is the", "images": [], "options": {"A": "terms of reference", "B": "body", "C": "findings", "D": "conclusion"}, "answer": "C", "explanation": "The highlights of an investigatory committee's assignment are usually stated in the 'findings' section of a report. This is where the main results or discoveries from the investigation are summarized. The 'terms of reference' is the section that outlines the purpose and scope of the investigation, the 'body' is the main part of the report where the investigation is detailed, and the 'conclusion' is where the findings are interpreted and recommendations are made.", "marks": "1", "difficulty": "2"}, {"id": "objective>Office Practice>2019>42", "subject": "Office Practice", "year": "2019", "type": "Objective", "topic": "THE OFFICE : LAYOUT OF AN OFFICE", "question": "An example of open office in a school is the", "images": [], "options": {"A": "principal's office", "B": "staff room", "C": "bursar's office", "D": "security post"}, "answer": "B", "explanation": "An open office is a concept where multiple people work in the same space, often without physical barriers such as walls or cubicles. In a school, the 'staff room' is an example of an open office because it is a shared space where multiple staff members can work. The 'principal's office', 'bursar's office', and 'security post' are typically separate, enclosed spaces.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2019>43", "subject": "Office Practice", "year": "2019", "type": "Objective", "topic": "MAILS : PROCEDURES FOR HANDLING INCOMING AND OUTGOING MAILS", "question": "One of the duties of a mail room clerk is to", "images": [], "options": {"A": "sort outgoing mail into department.", "B": "ensure that enclosures are attached to outgoing mail.", "C": "give advance notice to addresses of incoming mail.", "D": "return uncleared letters to the writers."}, "answer": "A", "explanation": "A mail room clerk is responsible for managing the mail within an organization. This includes sorting outgoing mail into departments, which is the correct answer. Ensuring that enclosures are attached to outgoing mail is also a duty of a mail room clerk, but it is not the only one. Giving advance notice to addresses of incoming mail and returning uncleared letters to the writers are not typically duties of a mail room clerk.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2019>44", "subject": "Office Practice", "year": "2019", "type": "Objective", "topic": "OFFICE CORRESPONDENCE : TYPES", "question": "Standardized letters which give the same information and reply to regular inquires and requests are", "images": [], "options": {"A": "personal letters", "B": "confidential letters", "C": "business letters", "D": "form letters"}, "answer": "D", "explanation": "Form letters are standardized letters that are used to give the same information and reply to regular inquiries and requests. They are often used in businesses where the same information needs to be sent to many people, such as notifications of a change in policy or procedure.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2019>45", "subject": "Office Practice", "year": "2019", "type": "Objective", "topic": "COMMUNICATION : METHODS/MEDIA OF COMMUNICATION", "question": "The use of a picture to convey information to receiver is an example of", "images": [], "options": {"A": "audio communication", "B": "visual communication", "C": "oral communication", "D": "written communication"}, "answer": "B", "explanation": "Visual communication is the use of visual elements to convey information or ideas. This can include pictures, diagrams, charts, and other visual aids. In this case, the use of a picture to convey information to a receiver is an example of visual communication.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2019>46", "subject": "Office Practice", "year": "2019", "type": "Objective", "topic": "COMMUNICATION : DEFINITION OF COMMUNICATION", "question": "The process of interpreting a received message is", "images": [], "options": {"A": "ideation", "B": "encoding", "C": "decoding", "D": "feedback"}, "answer": "C", "explanation": "Decoding is the process of interpreting a received message. In communication, once a message is received, the receiver interprets or 'decodes' the message to understand its meaning. This involves interpreting the words, symbols, and other forms of communication used in the message.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2019>47", "subject": "Office Practice", "year": "2019", "type": "Objective", "topic": "COMMUNICATION : METHODS/MEDIA OF COMMUNICATION", "question": "The means of internal communication in an organization is", "images": [], "options": {"A": "letter", "B": "circular", "C": "report", "D": "catalogue"}, "answer": "B", "explanation": "Internal communication in an organization is often done through circulars. A circular is a letter or notice intended for mass distribution within an organization. It is used to disseminate information or instructions to employees within the organization. Therefore, the correct answer is 'circular'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2019>48", "subject": "Office Practice", "year": "2019", "type": "Objective", "topic": "OFFICE DOCUMENTS : MEANING OF OFFICE DOCUMENT", "question": "A document from the seller to the buyer showing the date, description and quantity of goods supplies is", "images": [], "options": {"A": "debit note", "B": "requisition note", "C": "credit note", "D": "delivery note"}, "answer": "D", "explanation": "A document from the seller to the buyer showing the date, description, and quantity of goods supplied is a delivery note. A delivery note is a document that accompanies a goods shipment and lists details about the goods delivered. A delivery note is generally used by the receiver of the shipment to confirm the receipt of the goods. Therefore, the correct answer is 'delivery note'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2019>49", "subject": "Office Practice", "year": "2019", "type": "Objective", "topic": "THE RECEPTION : DUTIES", "question": "In an organization, a receptionist may sometimes act as", "images": [], "options": {"A": "a telephonist", "B": "an office supervisor", "C": "a secretary", "D": "a marketing officer"}, "answer": "A", "explanation": "In an organization, a receptionist may sometimes act as a telephonist. A telephonist is a person who operates a telephone switchboard, especially as a job. In many organizations, the receptionist's duties often include answering and directing phone calls, which is the role of a telephonist. Therefore, the correct answer is 'a telephonist'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2019>50", "subject": "Office Practice", "year": "2019", "type": "Objective", "topic": "MEETINGS : DEFINITION OF MEETING", "question": "The tenure of an ad-hoc committee is", "images": [], "options": {"A": "six month only.", "B": "one year only.", "C": "the period of its assignment.", "D": "determined by the chairman."}, "answer": "C", "explanation": "An ad-hoc committee is a temporary committee set up to accomplish a specific task or objective. The tenure of an ad-hoc committee is therefore the period of its assignment. Once the task or objective is accomplished, the committee is dissolved.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2020>1", "subject": "Office Practice", "year": "2020", "type": "Objective", "topic": "MEETINGS : TYPES", "question": "A meeting of AYEX Plc board of directors would be categorized as", "images": [], "options": {"A": "formal meeting", "B": "informal meeting", "C": "stakeholder meeting", "D": "staff meeting"}, "answer": "A", "explanation": "A meeting of a company's board of directors is a formal meeting. This is because it is usually structured, follows a set agenda, and is often documented in minutes. Informal meetings are less structured and may not follow a set agenda. Stakeholder meetings involve various parties who have an interest in the company, while staff meetings involve employees of the company.", "marks": "1", "difficulty": "2"}, {"id": "objective>Office Practice>2020>2", "subject": "Office Practice", "year": "2020", "type": "Objective", "topic": "FILING : CLASSIFICATION OF FILING", "question": "In alphabetical filing, professional titles are written", "images": [], "options": {"A": "after the names of people", "B": "in between the initials of people", "C": "after the surname of people", "D": "before the second name of people"}, "answer": "A", "explanation": "In alphabetical filing, professional titles are written after the names of people. This is because the primary sorting criterion in alphabetical filing is the name (usually the surname) of the individual. The professional title is secondary information and is therefore written after the name.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2020>3", "subject": "Office Practice", "year": "2020", "type": "Objective", "topic": "COMMUNICATION : METHODS/MEDIA OF COMMUNICATION", "question": "An advantages of oral communication is that it", "images": [], "options": {"A": "provides a permanent record of idea shared", "B": "carries more weight than other types of communication", "C": "is more formal than written communication", "D": "allows both parties concern to feel each other's mood"}, "answer": "D", "explanation": "Oral communication allows both parties to feel each other's mood. This is because it involves direct face-to-face conversation, which allows for immediate feedback and the ability to read non-verbal cues, such as body language and tone of voice. This is not possible in other forms of communication like written communication.", "marks": "1", "difficulty": "2"}, {"id": "objective>Office Practice>2020>4", "subject": "Office Practice", "year": "2020", "type": "Objective", "topic": "MAILS : PROCEDURES FOR HANDLING INCOMING AND OUTGOING MAILS", "question": "Incoming mails should be sorted according to", "images": [], "options": {"A": "sizes", "B": "weighs", "C": "departments", "D": "contents"}, "answer": "C", "explanation": "Incoming mails should be sorted according to departments. This is because each department in an organization typically handles different aspects of the business, and therefore, the information contained in the mails would be relevant to specific departments. Sorting mails according to departments ensures that the right information gets to the right people in a timely manner.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2020>5", "subject": "Office Practice", "year": "2020", "type": "Objective", "topic": "MEETINGS : PROCEDURES FOR CONDUCTING A MEETING", "question": "One of the common items included in the agenda of meeting is", "images": [], "options": {"A": "security issues in different parts of the country", "B": "security of members at the meeting", "C": "matters arising from the minutes of previous meeting", "D": "matters arising from the current meeting"}, "answer": "C", "explanation": "One of the common items included in the agenda of a meeting is 'matters arising from the minutes of the previous meeting'. This is because it is important to follow up on the issues discussed in the previous meeting, check the progress made, and determine if any further action is needed. This helps to ensure that all issues are addressed and nothing is overlooked.", "marks": "1", "difficulty": "2"}, {"id": "objective>Office Practice>2020>6", "subject": "Office Practice", "year": "2020", "type": "Objective", "topic": "OFFICE CORRESPONDENCE : MEANING OF OFFICE CORRESPONDENCE", "question": "Which of the following items in a letter is an example of complimentary close?", "images": [], "options": {"A": "Dear sir", "B": "Yours faithfully", "C": "Attention: Mr Smith", "D": "cc: Mrs Dauda"}, "answer": "B", "explanation": "The complimentary close in a letter is a polite way of ending the letter. It usually comes before the signature and after the body of the letter. 'Yours faithfully' is an example of a complimentary close.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2020>7", "subject": "Office Practice", "year": "2020", "type": "Objective", "topic": "OFFICE DOCUMENTS : MEANING OF OFFICE DOCUMENT", "question": "The implication of issuing a crossed cheque is that it can only be", "images": [], "options": {"A": "cashed at the counter", "B": "cash after six month of its issue", "C": "lodged into the current account of the payee", "D": "lodged into the fixed deposit account"}, "answer": "C", "explanation": "A crossed cheque is a cheque that has been marked to specify an instruction about the way it is to be redeemed. A crossed cheque cannot be immediately cashed at a bank counter but must be deposited into the bank account of the payee.", "marks": "1", "difficulty": "2"}, {"id": "objective>Office Practice>2020>8", "subject": "Office Practice", "year": "2020", "type": "Objective", "topic": "REPORT WRITINGS : PARTS OF A REPORT", "question": "The part of a report that suggets solution to the problem investigated is the", "images": [], "options": {"A": "body of report", "B": "recommendation", "C": "terms of reference", "D": "introduction"}, "answer": "B", "explanation": "The recommendation section of a report is where the author suggests solutions to the problems investigated in the report. It is where the author gives their advice on what actions should be taken.", "marks": "1", "difficulty": "2"}, {"id": "objective>Office Practice>2020>9", "subject": "Office Practice", "year": "2020", "type": "Objective", "topic": "OFFICE CORRESPONDENCE : TYPES", "question": "An official written message to several people at different destinations on the same subject matter is", "images": [], "options": {"A": "memo", "B": "letter", "C": "circular", "D": "report"}, "answer": "C", "explanation": "A circular is an official written message that is sent to several people at different destinations on the same subject matter. It is used to communicate the same information to a large number of people. A memo is a note or record made for future use. A letter is a written message from one party to another containing information. A report is a formal account of the facts or details of a matter.", "marks": "1", "difficulty": "2"}, {"id": "objective>Office Practice>2020>10", "subject": "Office Practice", "year": "2020", "type": "Objective", "topic": "MAILS : PROCEDURES FOR HANDLING INCOMING AND OUTGOING MAILS", "question": "Confidential mail is opened by the", "images": [], "options": {"A": "secretary", "B": "mail room staff", "C": "personnel unit staff", "D": "receptionist"}, "answer": "B", "explanation": "Mail romm staff is a person who works in a mailroom and is known as a mailroom clerk or mailboy and the head person (sometimes the only person is called the postmaster.The mailroom is responsible for a company's incoming and outgoing mail.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2020>11", "subject": "Office Practice", "year": "2020", "type": "Objective", "topic": "MEETINGS : PROCEDURES FOR CONDUCTING A MEETING", "question": "A form of corresponding sent to members asking them to attend a meeting is", "images": [], "options": {"A": "the minutes", "B": "an invite", "C": "a notice", "D": "an agenda"}, "answer": "C", "explanation": "A notice is a form of correspondence sent to members asking them to attend a meeting. It serves to inform members about the meeting and its details such as the date, time, and venue. An invite is a request, encouragement, or opportunity to do something. The minutes are the official record of the proceedings of a meeting. An agenda is a list of items to be discussed at a formal meeting.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2020>12", "subject": "Office Practice", "year": "2020", "type": "Objective", "topic": "OFFICE DOCUMENTS : USES", "question": "Business document are used for passing information on business transactions among", "images": [], "options": {"A": "buyers of goods and services only", "B": "sellers of goods and services only", "C": "buyer and sellers of goods and services only", "D": "competitors of the organization only"}, "answer": "C", "explanation": "Business documents are used for passing information on business transactions among both buyers and sellers of goods and services. These documents can include things like invoices, receipts, purchase orders, and more. They are used to keep track of transactions, provide legal protection, and ensure clear communication between parties.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2020>13", "subject": "Office Practice", "year": "2020", "type": "Objective", "topic": "MEETINGS : TYPES", "question": "A meeting held by all employees of an organization is", "images": [], "options": {"A": "a committee meeting", "B": "an emergency meeting", "C": "a staff meeting", "D": "an annual general meeting"}, "answer": "C", "explanation": "A meeting held by all employees of an organization is typically referred to as a staff meeting. This is a regular meeting where information is shared, updates are given, and issues are discussed. It's a way for everyone in the organization to stay informed and aligned.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2020>14", "subject": "Office Practice", "year": "2020", "type": "Objective", "topic": "FILING : STEPS IN FILING", "question": "The act of weeding out redundant documents in the files is", "images": [], "options": {"A": "up-dating of records", "B": "thining of records", "C": "destruction of records", "D": "removing of records"}, "answer": "B", "explanation": "The act of weeding out redundant documents in the files is referred to as thinning of records. This process involves removing duplicate, outdated, or unnecessary documents from a file or record system. It's a way to keep records organized and manageable, and to ensure that the most relevant and up-to-date information is easily accessible.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2020>15", "subject": "Office Practice", "year": "2020", "type": "Objective", "topic": "REPORT WRITINGS : TYPES", "question": "A report written regularly to give an account of an event or work carried out is", "images": [], "options": {"A": "a periodic report", "B": "a statutory report", "C": "a routine report", "D": "an informal report"}, "answer": "C", "explanation": "A routine report is a type of report that is written on a regular or scheduled basis. This could be daily, weekly, monthly, or annually. It is used to provide an update or give an account of an event or work carried out regularly. A periodic report is also regular but it is not necessarily about an event or work carried out. A statutory report is a report that is legally required, while an informal report is a casual report usually meant for internal distribution.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2020>16", "subject": "Office Practice", "year": "2020", "type": "Objective", "topic": "OFFICE EQUIPMENT : TYPES OF OFFICE EQUIPMENT", "question": "An electirc device which process data into information by following a set of programme instructions is", "images": [], "options": {"A": "computer", "B": "teleprinter", "C": "photocopier", "D": "calculator"}, "answer": "A", "explanation": "A computer is an electronic device that manipulates information, or data. It has the ability to store, retrieve, and process data. It follows a set of program instructions to process data into information. A teleprinter is a telegraph machine that can send and receive messages, a photocopier is a machine that makes paper copies of documents and other visual images, and a calculator is a device that is used for performing numerical calculations.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2020>17", "subject": "Office Practice", "year": "2020", "type": "Objective", "topic": "COMMUNICATION : METHODS/MEDIA OF COMMUNICATION", "question": "The first step the sender takes into the communication process is to", "images": [], "options": {"A": "transmit the message", "B": "encode the message", "C": "select an appropriate channel", "D": "give a feedback"}, "answer": "B", "explanation": "The first step in the communication process is to encode the message. Encoding is the process of turning thoughts into communication. The sender has an intention to communicate and hence, creates a message in their mind, which is then encoded in a way that can be understood by the receiver. Transmitting the message, selecting an appropriate channel, and giving feedback are subsequent steps in the communication process.", "marks": "1", "difficulty": "2"}, {"id": "objective>Office Practice>2020>18", "subject": "Office Practice", "year": "2020", "type": "Objective", "topic": "MEETINGS : WRITING THE MINUTES", "question": "A record of the proceedings of a meeting that is circulated to members is the", "images": [], "options": {"A": "quorum", "B": "agenda", "C": "minutes", "D": "motion"}, "answer": "C", "explanation": "The record of the proceedings of a meeting that is circulated to members is known as the 'minutes'. Minutes are the written record of a meeting or hearing. They typically describe the events of the meeting, starting with a list of attendees, a statement of the issues considered by the participants, and related responses or decisions for the issues.", "marks": "1", "difficulty": "2"}, {"id": "objective>Office Practice>2020>19", "subject": "Office Practice", "year": "2020", "type": "Objective", "topic": "COMMUNICATION : DEFINITION OF COMMUNICATION", "question": "Which of the following is a barrier to effective communication?", "images": [], "options": {"A": "Encoding", "B": "Decoding", "C": "Channel", "D": "Noise"}, "answer": "D", "explanation": "Noise is a barrier to effective communication. In the context of communication, 'noise' refers to anything that distorts the message, making it difficult for the receiver to understand the message as intended by the sender. This could be physical noise (like loud sounds) or psychological noise (like distractions, stress, or language differences).", "marks": "1", "difficulty": "2"}, {"id": "objective>Office Practice>2020>20", "subject": "Office Practice", "year": "2020", "type": "Objective", "topic": "FILING : SYSTEMS OF FILING", "question": "A system whereby all files and records of an organization are kept and controlled in one room is", "images": [], "options": {"A": "decentralized filing", "B": "vertical filing", "C": "centralized filing", "D": "horizontal filing"}, "answer": "C", "explanation": "A system whereby all files and records of an organization are kept and controlled in one room is known as 'centralized filing'. Centralized filing is a structured filing system in one location. It is easier to control and coordinate and it ensures that the files are safe and easily accessible when needed.", "marks": "1", "difficulty": "2"}, {"id": "objective>Office Practice>2020>21", "subject": "Office Practice", "year": "2020", "type": "Objective", "topic": "REPORT WRITINGS : PARTS OF A REPORT", "question": "The part of a report giving a detailed explanation of how a committe carried out its assignment is the", "images": [], "options": {"A": "introduction", "B": "terms of reference", "C": "body", "D": "recommendation"}, "answer": "C", "explanation": "The body of a report is where the detailed explanation of how a committee carried out its assignment is found. The introduction usually provides a brief overview of the report's content, the terms of reference define the purpose and structure of the report, and the recommendation is where suggestions or conclusions are made based on the findings in the report.", "marks": "1", "difficulty": "2"}, {"id": "objective>Office Practice>2020>22", "subject": "Office Practice", "year": "2020", "type": "Objective", "topic": "OFFICE EQUIPMENT : TYPES OF OFFICE EQUIPMENT", "question": "An advantage of eletric typewriter over manual typewriter is that", "images": [], "options": {"A": "they are faster and increase output", "B": "they are less expensive to buy", "C": "the cost of maintenance is lower", "D": "they can be easily moved from place to place"}, "answer": "A", "explanation": "Electric typewriters are indeed faster and increase output compared to manual typewriters. This is because electric typewriters are powered by electricity and have keys that require less force to press, resulting in faster typing speeds. The other options are incorrect as electric typewriters are generally more expensive to buy, have higher maintenance costs due to their complexity, and are not easily portable due to their reliance on electricity.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2020>23", "subject": "Office Practice", "year": "2020", "type": "Objective", "topic": "DEPARTMENTS IN AN ORGANIZATION : FUNCTIONS OF EACH DEPARTMENT", "question": "The purchasing department in an organization is responsible for", "images": [], "options": {"A": "procurring goods for the organization", "B": "selling ggods for the organization", "C": "advertising goods for the organization", "D": "recording goods for the organization"}, "answer": "A", "explanation": "The purchasing department in an organization is responsible for procuring goods for the organization. This involves identifying suppliers, negotiating contracts, and ensuring that the goods are delivered on time and meet the organization's quality standards. The other options are incorrect as selling, advertising, and recording goods are typically responsibilities of the sales, marketing, and inventory departments respectively.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2020>24", "subject": "Office Practice", "year": "2020", "type": "Objective", "topic": "THE RECEPTION : MEANING OF RECEPTIONIST", "question": "Use the following information to answer questions below:  Adams has just been employed by a large organization as the first person whom callers and visitors would see when visiting the organization    Which of the following postion does Adams occupy in the organization?", "images": [], "options": {"A": "Manager", "B": "Supervisor", "C": "Receptionist", "D": "Secretary"}, "answer": "C", "explanation": "The first person whom callers and visitors would see when visiting an organization is typically the Receptionist. The receptionist's role is to greet visitors and direct them to the appropriate person or department. They also handle incoming calls and often perform administrative tasks.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2020>25", "subject": "Office Practice", "year": "2020", "type": "Objective", "topic": "COMMUNICATION : IMPORTANCE", "question": "Use the following information to answer questions below:  Adams has just been employed by a large organization as the first person whom callers and visitors would see when visiting the organizationIn order to perform his duties well,Adams must be able to", "images": [], "options": {"A": "communicate effectively", "B": "supervise effectively", "C": "coordinate effectively", "D": "handle mails effectively"}, "answer": "A", "explanation": "In order to perform his duties well, Adams must be able to communicate effectively. As a receptionist, he will be interacting with a variety of people, including clients, visitors, and staff members. Effective communication skills are essential to ensure that information is conveyed accurately and professionally.", "marks": "1", "difficulty": "2"}, {"id": "objective>Office Practice>2020>26", "subject": "Office Practice", "year": "2020", "type": "Objective", "topic": "THE RECEPTION : DOCUMENTS HANDLED BY A RECEPTIONIST", "question": "Use the following information to answer questions below:  Adams has just been employed by a large organization as the first person whom callers and visitors would see when visiting the organizationTo keep records of callers and clients who come for the organization,Adams office must be provided with", "images": [], "options": {"A": "attendance register", "B": "visitors' book", "C": "mail register", "D": "dispatch book"}, "answer": "B", "explanation": "To keep records of callers and clients who come for the organization, Adams' office must be provided with a visitors' book. This is a record where visitors sign in with their name, the date and time of their visit, who they are seeing and their purpose of visit. It helps the organization keep track of who is coming and going.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2020>27", "subject": "Office Practice", "year": "2020", "type": "Objective", "topic": "THE OFFICE : LAYOUT OF AN OFFICE", "question": "A feature of an open office is that", "images": [], "options": {"A": "all the doors are opened", "B": "all the cabinets are opened", "C": "workers are put together in the same room", "D": "each worker occupies a separate room"}, "answer": "C", "explanation": "An open office is a type of office layout where all or most employees work in the same room, often at desks arranged in a grid pattern. This layout is designed to facilitate communication and collaboration among employees. Therefore, the correct answer is 'workers are put together in the same room'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Office Practice>2020>28", "subject": "Office Practice", "year": "2020", "type": "Objective", "topic": "MAILS : PROCEDURES FOR HANDLING INCOMING AND OUTGOING MAILS", "question": "The first step a mail clerk takes in handling outgoing mail is to", "images": [], "options": {"A": "collect typed letters from various departments", "B": "attach all enclosure that are to accompany each mail", "C": "date-stamp the envelop in which each letter is inverted", "D": "ensure that each mail envelop is well-sealed"}, "answer": "A", "explanation": "The first step a mail clerk takes in handling outgoing mail is to collect the typed letters from various departments. This is because before any other action can be taken, such as attaching enclosures or date-stamping envelopes, the mail clerk must first have the letters that are to be sent out.", "marks": "1", "difficulty": "2"}, {"id": "objective>Office Practice>2020>29", "subject": "Office Practice", "year": "2020", "type": "Objective", "topic": "INFORMATION : STORAGE OF INFORMATION", "question": "The means of making miniature copies of records for storage is", "images": [], "options": {"A": "indexing", "B": "microfilming", "C": "cross-referencing", "D": "jogger"}, "answer": "B", "explanation": "Microfilming is a process that involves making miniature copies of documents for storage. This is done by photographing the documents and storing the images on film. When needed, the images can be enlarged and viewed. Therefore, the correct answer is 'microfilming'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2020>30", "subject": "Office Practice", "year": "2020", "type": "Objective", "topic": "COMMUNICATION : METHODS/MEDIA OF COMMUNICATION", "question": "Information on a specific project to all members of a section is communicated through", "images": [], "options": {"A": "departmental meetings", "B": "board meetings", "C": "annual meetings", "D": "executive meetings"}, "answer": "A", "explanation": "Information on a specific project to all members of a section is usually communicated through departmental meetings. This is because departmental meetings are designed to disseminate information and discuss matters that concern a specific department or section within an organization. Board meetings, annual meetings, and executive meetings are typically for higher-level strategic discussions and may not involve all members of a specific section.", "marks": "1", "difficulty": "2"}, {"id": "objective>Office Practice>2020>31", "subject": "Office Practice", "year": "2020", "type": "Objective", "topic": "INFORMATION : TYPES", "question": "The information written on a paper would be regarded as the", "images": [], "options": {"A": "soft copy", "B": "blind copy", "C": "hard copy", "D": "photocopy"}, "answer": "C", "explanation": "The information written on a paper would be regarded as the hard copy. A hard copy is a physical version of information, such as a document, that is printed on paper. In contrast, a soft copy is a digital version of these documents, which can be stored and viewed on a computer. A blind copy refers to sending emails to recipients in such a way that they can't see the other recipients, and a photocopy is a duplicate of a document or print made on a photocopier.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2020>32", "subject": "Office Practice", "year": "2020", "type": "Objective", "topic": "COMMUNICATION : METHODS/MEDIA OF COMMUNICATION", "question": "A memo is used in an office for", "images": [], "options": {"A": "internal communication", "B": "oral communication", "C": "external communication", "D": "audio communication"}, "answer": "A", "explanation": "A memo (short for memorandum) is a type of document used in businesses for internal communication. Memos are typically used within an organization to communicate information, changes, or updates to employees. Therefore, memos are not used for oral, external, or audio communication.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2020>33", "subject": "Office Practice", "year": "2020", "type": "Objective", "topic": "OFFICE EQUIPMENT : MEANING OF OFFICE EQUIPMENT", "question": "One of the disdavantages of using office machine is that it leads to", "images": [], "options": {"A": "reduction in running cost", "B": "low productivity", "C": "low quality of work", "D": "staff redundancy"}, "answer": "D", "explanation": "The use of office machines can lead to staff redundancy. This is because machines can often perform tasks more efficiently and quickly than humans, reducing the need for human labor. This can lead to job losses, which is a major disadvantage of using office machines.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2020>34", "subject": "Office Practice", "year": "2020", "type": "Objective", "topic": "OFFICE DOCUMENTS : PREPARATION OF OFFICE DOCUMENTS", "question": "Price list is issued by the seller to", "images": [], "options": {"A": "make enquires about products and their prices", "B": "serve as reply to a customer's enquiry", "C": "make order for goods and services", "D": "make enquires about products and means of payment"}, "answer": "B", "explanation": "A price list is issued by the seller to serve as a reply to a customer's enquiry. It provides information about the products and their prices, allowing the customer to make an informed decision about their purchase.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2020>35", "subject": "Office Practice", "year": "2020", "type": "Objective", "topic": "MAILS : PROCEDURES FOR HANDLING INCOMING AND OUTGOING MAILS", "question": "Which of the following headings is a column in a postage book", "images": [], "options": {"A": "Date of dispatch", "B": "Value of stamp used", "C": "Reference number", "D": "Title of document"}, "answer": "B", "explanation": "A postage book is a record of all the mail that has been sent out, including the value of the stamp used. This allows for tracking of expenses and ensures that the correct amount of postage is being used for each item.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2020>36", "subject": "Office Practice", "year": "2020", "type": "Objective", "topic": "OFFICE EQUIPMENT : TYPES OF OFFICE EQUIPMENT", "question": "The machine used to produce large number of copies of a document from the", "images": [], "options": {"A": "electronic typewriter", "B": "collating machine", "C": "duplicating machine", "D": "scanning machine"}, "answer": "C", "explanation": "A duplicating machine is used to produce a large number of copies of a document. This process is also known as duplication. The machine works by creating a master copy of the document, which is then used to produce the copies. The other options listed do not perform this function. An electronic typewriter is used for typing, a collating machine is used for arranging papers in a specific order, and a scanning machine is used for creating digital copies of documents.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2020>37", "subject": "Office Practice", "year": "2020", "type": "Objective", "topic": "DEPARTMENTS IN AN ORGANIZATION : ORGANIZATIONAL CHART", "question": "Use the diagram below to answer questions below       The downward arrows shows", "images": ["Office Practice/imgs/2020/ssceoffice2020q37.png"], "options": {"A": "supervisory relationship", "B": "lateral relationship", "C": "reporting relationship", "D": "lateral and reporting relationships"}, "answer": "D", "explanation": "Lateral relationship/structural arrangement consists of a decentralized structure in which departments works together to acheive a common goal rather than operate as separate and distinct entities.", "marks": "1", "difficulty": "3"}, {"id": "objective>Office Practice>2020>38", "subject": "Office Practice", "year": "2020", "type": "Objective", "topic": "DEPARTMENTS IN AN ORGANIZATION : ORGANIZATIONAL CHART", "question": "Use the diagram below to answer questions below     The upward arrows shows", "images": ["Office Practice/imgs/2020/ssceoffice2020q37.png"], "options": {"A": "supervisory relationship", "B": "lateral relationship", "C": "reporting relationship", "D": "lateral and reporting relationships"}, "answer": "A", "explanation": "Supervisory relationship is merely a way of connecting a supervisor who is more experienced or an expertise, with a supervisee who lacks this experience.Both of them have some common goals and work together to acheive these goals.", "marks": "1", "difficulty": "3"}, {"id": "objective>Office Practice>2020>39", "subject": "Office Practice", "year": "2020", "type": "Objective", "topic": "FILING : CLASSIFICATION OF FILING", "question": "Use the diagram below to answer questions below     Which of the following names comes first in alphabetical filing?", "images": ["Office Practice/imgs/2020/ssceoffice2020q37.png"], "options": {"A": "R.A.D Johnson", "B": "A.R.D Johnson", "C": "Dr. R.A.D Johnson", "D": "Dr. A.R.D Johnson"}, "answer": "D", "explanation": "Alphabetical filing is a method in which files and folders are arranged in order of alphabets of the names of person or institution concerned with such file. It may be dome using either the first names or surnames, but whichever is chosen must be consistent throughout the particular filing system. However, initial comes first before the names.", "marks": "1", "difficulty": "3"}, {"id": "objective>Office Practice>2020>40", "subject": "Office Practice", "year": "2020", "type": "Objective", "topic": "THE OFFICE : FUNCTIONS OF OFFICE", "question": "One of the functions of an office is to safeguard", "images": [], "options": {"A": "information", "B": "assets", "C": "payment vouchers", "D": "visitor's book"}, "answer": "A", "explanation": "One of the primary functions of an office is to safeguard information. This includes data, records, and any other form of information that is crucial to the operation of the organization. While assets, payment vouchers, and visitor's books are also important, they are not the primary function of an office.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2020>41", "subject": "Office Practice", "year": "2020", "type": "Objective", "topic": "MAILS : PROCEDURES FOR HANDLING INCOMING AND OUTGOING MAILS", "question": "In a large organization,mails handling is done in the", "images": [], "options": {"A": "reception", "B": "registry", "C": "general office", "D": "secretary's office"}, "answer": "B", "explanation": "In a large organization, mail handling is typically done in the registry. The registry is responsible for receiving, sorting, and distributing mail within the organization. The reception is usually the first point of contact for visitors, the general office handles a variety of administrative tasks, and the secretary's office is typically responsible for supporting the work of a specific individual or department.", "marks": "1", "difficulty": "2"}, {"id": "objective>Office Practice>2020>42", "subject": "Office Practice", "year": "2020", "type": "Objective", "topic": "OFFICE EQUIPMENT : TYPES OF OFFICE EQUIPMENT", "question": "The office machine used for fastening papers together is a", "images": [], "options": {"A": "perforator", "B": "stapler", "C": "fokling machine", "D": "sealing machine"}, "answer": "B", "explanation": "A stapler is an office tool that is used to join together pages of paper or similar material by driving a thin metal staple through the sheets and folding the ends. Therefore, the correct answer is a stapler.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2020>43", "subject": "Office Practice", "year": "2020", "type": "Objective", "topic": "THE OFFICE : LAYOUT OF AN OFFICE", "question": "One of the advantages of a closed office is that", "images": [], "options": {"A": "the supervisor can see all workers at a glance", "B": "it is easy to construct", "C": "office equipment can be jointly used", "D": "it ensure confidentially of documents"}, "answer": "D", "explanation": "A closed office layout is a type of office layout where all the office spaces are divided by walls and each employee has their own separate office space. This type of office layout is beneficial for jobs that require concentration, privacy and confidentiality. Therefore, the correct answer is 'it ensures confidentiality of documents'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Office Practice>2020>44", "subject": "Office Practice", "year": "2020", "type": "Objective", "topic": "FILING : CLASSIFICATION OF FILING", "question": "The appropriate filing classification for an organization having clients in different locations is", "images": [], "options": {"A": "alphabetical", "B": "numerical", "C": "chronological", "D": "geographical"}, "answer": "D", "explanation": "Geographical filing is a method where files and folders are arranged in order of geographical location. This method is useful for organizations that operate in different geographical locations. Therefore, the correct answer is 'geographical'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Office Practice>2020>45", "subject": "Office Practice", "year": "2020", "type": "Objective", "topic": "COMMUNICATION : DEFINITION OF COMMUNICATION", "question": "The exchange of information among individuals is", "images": [], "options": {"A": "coding", "B": "decoding", "C": "communication", "D": "feedback"}, "answer": "C", "explanation": "Communication is the process of exchanging information or ideas between two or more individuals. Coding and decoding are parts of the communication process, while feedback is a response to the communication.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2020>46", "subject": "Office Practice", "year": "2020", "type": "Objective", "topic": "COMMUNICATION : METHODS/MEDIA OF COMMUNICATION", "question": "An example of traditional method of communication is", "images": [], "options": {"A": "drumming", "B": "telephoning", "C": "letter writing", "D": "speech making"}, "answer": "A", "explanation": "Drumming is a traditional method of communication, especially in African societies. Telephoning, letter writing, and speech making are modern methods of communication.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2020>47", "subject": "Office Practice", "year": "2020", "type": "Objective", "topic": "INFORMATION : SOURCES", "question": "The source of business information which gives spellings and meanings of words is the", "images": [], "options": {"A": "diary", "B": "dictionary", "C": "directory", "D": "harzard"}, "answer": "B", "explanation": "A dictionary is a source of business information that provides spellings and meanings of words. A diary is a record of personal experiences and observations, a directory is a list of names, addresses, and other details, and a hazard is a potential source of danger.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2020>48", "subject": "Office Practice", "year": "2020", "type": "Objective", "topic": "THE OFFICE : FUNCTIONS OF OFFICE", "question": "Which of the following activities is a function of an office?", "images": [], "options": {"A": "Receiving information", "B": "Punishing late comers", "C": "Calculating of workers salaries", "D": "Welcoming visitors"}, "answer": "A", "explanation": "An office function involves the management and distribution of information. This includes receiving, processing, storing, and disseminating information. Therefore, 'Receiving information' is a function of an office.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2020>49", "subject": "Office Practice", "year": "2020", "type": "Objective", "topic": "MEETINGS : TYPES", "question": "An executive committee can be described as one which", "images": [], "options": {"A": "has no power to ratift decisions of other committees", "B": "has power to ratify decisions of other committees", "C": "is dissolved on the completion of its assignment", "D": "has no fixed assignment"}, "answer": "B", "explanation": "An executive committee is a smaller group of a larger board or organization that has the power to make decisions on behalf of the larger group. This includes the power to ratify decisions of other committees. Therefore, 'has power to ratify decisions of other committees' is the correct answer.", "marks": "1", "difficulty": "2"}, {"id": "objective>Office Practice>2020>50", "subject": "Office Practice", "year": "2020", "type": "Objective", "topic": "OFFICE DOCUMENTS : MEANING OF OFFICE DOCUMENT", "question": "The part of a letter which makes it an authentic office document is the", "images": [], "options": {"A": "address", "B": "salutation", "C": "enclosure", "D": "signature"}, "answer": "D", "explanation": "The signature part of a letter is what makes it an authentic office document. It is the signatory's endorsement of the content of the letter. Therefore, 'signature' is the correct answer.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2021>1", "subject": "Office Practice", "year": "2021", "type": "Objective", "topic": "OFFICE EQUIPMENT : TYPES OF OFFICE EQUIPMENT", "question": "The secreatary at ABC Company needs to produce a document in large quantity. Which of these office equipment would be used?", "images": [], "options": {"A": "Typewriter", "B": "Duplicator", "C": "Tele-printer", "D": "Risograph"}, "answer": "B", "explanation": "A duplicator is used to produce a large number of copies of a document. It works by creating a master copy of the document and then using it to print the copies. This is different from a typewriter, which is used for typing individual documents, or a tele-printer, which is used for sending and receiving typed messages. A Risograph is a high-speed digital printing system designed for high-volume copying and printing, but it's not as commonly used as a duplicator in an office setting.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2021>2", "subject": "Office Practice", "year": "2021", "type": "Objective", "topic": "COMMUNICATION : METHODS/MEDIA OF COMMUNICATION", "question": "A few copies of a written message to all members of staff in a large organization could be posted on", "images": [], "options": {"A": "billboards", "B": "notice boards", "C": "magic boards", "D": "Signboards"}, "answer": "B", "explanation": "Notice boards are typically used in large organizations to post written messages for all staff members to see. They are usually placed in common areas where they are easily visible. Billboards are large outdoor boards for displaying advertisements, and magic boards are interactive whiteboards used for presentations. Signboards are used to display information or directions, but they are not typically used to post messages for staff members.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2021>3", "subject": "Office Practice", "year": "2021", "type": "Objective", "topic": "MEETINGS : MEETING TERMINOLOGIES", "question": "A member who raises a motion at a meeting is a", "images": [], "options": {"A": "proposer", "B": "scrutinizer", "C": "convener", "D": "Proxy  ."}, "answer": "A", "explanation": "In the context of a meeting, the person who raises a motion is known as the proposer. The proposer initiates a process of debate and decision-making on a particular issue. A scrutinizer is someone who examines something closely, a convener is a person who brings together a group of people for a meeting, and a proxy is a person authorized to act for another.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2021>4", "subject": "Office Practice", "year": "2021", "type": "Objective", "topic": "FILING : SYSTEMS OF FILING", "question": "Miss Rosey, the clerical assistant at XYZ Ltd, keeps documents in the file according to dates received. This system of filing is", "images": [], "options": {"A": "geographical filing", "B": "chronological filing", "C": "alphabetical filing", "D": "subject filing"}, "answer": "B", "explanation": "Chronological filing is a method of filing documents in order of their date, either ascending or descending. This system is often used for things like invoices, bank statements, or reports that are often referred to by the date they were created or processed. In the given scenario, Miss Rosey is keeping documents in the file according to dates received, which is a characteristic of chronological filing.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2021>5", "subject": "Office Practice", "year": "2021", "type": "Objective", "topic": "INFORMATION : SOURCES", "question": "Ojo was aksed by his superior in the office to check up the continent where Australia is located. He would get his information from", "images": [], "options": {"A": "a city directory", "B": "a world's who is who", "C": "an encyclopedia", "D": "an atlas"}, "answer": "D", "explanation": "An atlas is a collection of maps; it is typically a map of Earth or a region of Earth, but there are atlases of the other planets (and their satellites) in the Solar System. Atlases have traditionally been bound into book form, but today many atlases are in multimedia formats. In the given scenario, Ojo can find the information about the continent where Australia is located in an atlas.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2021>6", "subject": "Office Practice", "year": "2021", "type": "Objective", "topic": "MEETINGS : WRITING THE MINUTES", "question": "The minutes of APX ventures meeting written by secretary was considered to be alright by members. This implies the the minutes is", "images": [], "options": {"A": "legible", "B": "concise", "C": "accurate", "D": "Flexible"}, "answer": "C", "explanation": "The minutes of a meeting are the official record of what was discussed and decided at that meeting. They should be accurate and include all the important details. If the minutes of APX ventures meeting written by the secretary were considered to be alright by members, this implies that the minutes were accurate.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2021>7", "subject": "Office Practice", "year": "2021", "type": "Objective", "topic": "OFFICE DOCUMENTS : TYPES", "question": "If goods are returned, the seller issues", "images": [], "options": {"A": "a debit notes", "B": "a consignment note", "C": "an advice note", "D": "a credit note"}, "answer": "D", "explanation": "When goods are returned by the buyer, the seller issues a credit note. A credit note is a document sent by a seller to its buyer, or, in other words, a vendor to the customer, notifying that a credit has been provided to their account. The reason for issuing a credit note are typically due to some returned goods or an overcharge on an invoice.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2021>8", "subject": "Office Practice", "year": "2021", "type": "Objective", "topic": "FILING : CLASSIFICATION OF FILING", "question": "Sule, the mail clerk at Ali Ltd, files some documents under two headings. For easy location of such document, he would make use of", "images": [], "options": {"A": "cross-referencing", "B": "coding", "C": "indexing", "D": "Microfilming"}, "answer": "A", "explanation": "Cross-referencing is the method Sule would use for easy location of such documents. Cross-referencing is a process of referencing an index or a point of data in a document or book to another piece of data elsewhere in the same document or book. It helps in locating information quickly and easily.", "marks": "1", "difficulty": "2"}, {"id": "objective>Office Practice>2021>9", "subject": "Office Practice", "year": "2021", "type": "Objective", "topic": "COMMUNICATION : METHODS/MEDIA OF COMMUNICATION", "question": "One of the advantages of visual communicaion is that it", "images": [], "options": {"A": "can be kept for future use", "B": "is cheap to produce", "C": "does not require extra skill to interpret", "D": "does not occupy space"}, "answer": "A", "explanation": "One of the advantages of visual communication is that it can be kept for future use. Visual communication involves the use of visual elements, such as drawings, illustrations and electronic images, to convey ideas and information. These visual elements can be stored and retrieved for future use.", "marks": "1", "difficulty": "2"}, {"id": "objective>Office Practice>2021>10", "subject": "Office Practice", "year": "2021", "type": "Objective", "topic": "INFORMATION : SOURCES", "question": "Which of the following reference books contains information about parliamentary proceedings?", "images": [], "options": {"A": "Hansards", "B": "Official gazatte", "C": "Atlas", "D": "Post office guide"}, "answer": "A", "explanation": "Hansards are the traditional name of the transcripts of Parliamentary Debates in Britain and many Commonwealth countries. It is named after Thomas Curson Hansard, a London printer and publisher, who was the first official printer to the parliament. Therefore, Hansards contain information about parliamentary proceedings.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2021>11", "subject": "Office Practice", "year": "2021", "type": "Objective", "topic": "REPORT WRITINGS : PARTS OF A REPORT", "question": "One of the essential parts of a report is", "images": [], "options": {"A": "reference", "B": "conclusion", "C": "salutation", "D": "enclosure"}, "answer": "B", "explanation": "A report is a document that presents information in an organized format for a specific audience and purpose. One of the essential parts of a report is the conclusion. The conclusion summarizes the report, it includes the results, analysis, and the final thoughts. It is where the author brings together their findings and comments on them.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2021>12", "subject": "Office Practice", "year": "2021", "type": "Objective", "topic": "COMMUNICATION : METHODS/MEDIA OF COMMUNICATION", "question": "Oral communication could be done through", "images": [], "options": {"A": "gesture", "B": "signs", "C": "postals", "D": "telephones"}, "answer": "D", "explanation": "Oral communication refers to the spoken word in the communication process. Oral communication can be either face-to-face communication or a conversation over the phone or on the voice chat over the internet. Therefore, telephones are a means through which oral communication could be done.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2021>13", "subject": "Office Practice", "year": "2021", "type": "Objective", "topic": "FILING : SYSTEMS OF FILING", "question": "One of the advantages of lateral filing system is that it", "images": [], "options": {"A": "economizes the use of space", "B": "is very easy to operate", "C": "does not require numbering", "D": "reduces the probability of losing documents"}, "answer": "A", "explanation": "A lateral filing system is a method of storing files horizontally in a cabinet. The advantage of this system is that it economizes the use of space. This is because files are stored side by side, which allows for more files to be stored in the same amount of space compared to vertical filing systems.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2021>14", "subject": "Office Practice", "year": "2021", "type": "Objective", "topic": "OFFICE CORRESPONDENCE : MEANING OF OFFICE CORRESPONDENCE", "question": "A correspondence could be described as", "images": [], "options": {"A": "an oral conversation between parties", "B": "a formal speech presented at an occasion", "C": "a written communication between two organizations", "D": "a message conveyed through the grapevine"}, "answer": "C", "explanation": "Correspondence refers to the exchange of written communication between two parties. This can be between individuals, organizations, or both. Therefore, a correspondence could be described as a written communication between two organizations.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2021>15", "subject": "Office Practice", "year": "2021", "type": "Objective", "topic": "REPORT WRITINGS : MEANING OR REPORT WRITING", "question": "A chief accountant tasked a five-member committee to look into an embezzlement case. After the completion of the assignment, the committee is required to come up with a", "images": [], "options": {"A": "memo", "B": "letter", "C": "report", "D": "minutes"}, "answer": "C", "explanation": "In a business setting, when a committee is tasked to look into a case, they are usually required to come up with a report after the completion of the assignment. This report would detail their findings and possibly recommendations. Therefore, the committee is required to come up with a report.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2021>16", "subject": "Office Practice", "year": "2021", "type": "Objective", "topic": "MAILS : PROCEDURES FOR HANDLING INCOMING AND OUTGOING MAILS", "question": "The acronym NIPOST stands for", "images": [], "options": {"A": "National Postal Service", "B": "Nigeria Postal Service", "C": "Nigerians Postal Services", "D": "Nigerian Postal Service"}, "answer": "D", "explanation": "The acronym NIPOST stands for Nigerian Postal Service. It is the company responsible for providing postal services in Nigeria.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2021>17", "subject": "Office Practice", "year": "2021", "type": "Objective", "topic": "OFFICE DOCUMENTS : MEANING OF OFFICE DOCUMENT", "question": "Use the document below to answer questions below    From: Administrative department    - which office document is shown above?", "images": [], "options": {"A": "Invoice", "B": "Suppliers form", "C": "Purchases requisition", "D": "Pro-forma invoice"}, "answer": "A", "explanation": "An invoice is a time-stamped commercial document that itemizes and records a transaction between a buyer and a seller. If goods or services were purchased on credit; the invoice usually specifies the terms of the deal and provides information on the available methods of payment.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2021>18", "subject": "Office Practice", "year": "2021", "type": "Objective", "topic": "DEPARTMENTS IN AN ORGANIZATION : FUNCTIONS OF EACH DEPARTMENT", "question": "Use the document below to answer questions below    From: Administrative department         - To which department would the document be submitted?", "images": [], "options": {"A": "Accounts", "B": "Purchasing", "C": "Production", "D": "Marketing"}, "answer": "A", "explanation": "In general, both types of invoices are processed by a company's accounts payable department. The process in which a supplier invoice is validated and paid is also known as the purchase -to- pay cycle.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2021>19", "subject": "Office Practice", "year": "2021", "type": "Objective", "topic": "COMMUNICATION : METHODS/MEDIA OF COMMUNICATION", "question": "One of the disadvantages of oral communication is that", "images": [], "options": {"A": "immediate feedback is not possible", "B": "information could be denied", "C": "it is very expensive", "D": "it does not promote cordiality"}, "answer": "B", "explanation": "Oral communication is a type of communication where we use words to exchange information with others. This can be face-to-face, over the phone, on the radio or television or other media. One of the disadvantages of oral communication is that it can be easily denied as there is often no record of the conversation. This makes it difficult to prove what was said or agreed upon.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2021>20", "subject": "Office Practice", "year": "2021", "type": "Objective", "topic": "MAILS : PROCEDURES FOR HANDLING INCOMING AND OUTGOING MAILS", "question": "The procedure to be followed by a mailroom clerk in handling incoming mails is", "images": [], "options": {"A": "receiving, sorting, opening scrutinizing", "B": "sorting, receiving, opening, scrutinizing", "C": "receiving, sorting, scrutinizing. opening", "D": "opening, receiving, sorting, scrutinizing"}, "answer": "A", "explanation": "The correct procedure for handling incoming mails by a mailroom clerk is: receiving, sorting, opening, and scrutinizing. Receiving is the first step where the clerk accepts the mail. Sorting is the next step where the mail is categorized based on certain criteria. Opening is the third step where the mail is opened to reveal its contents. Scrutinizing is the final step where the contents of the mail are carefully examined.", "marks": "1", "difficulty": "2"}, {"id": "objective>Office Practice>2021>21", "subject": "Office Practice", "year": "2021", "type": "Objective", "topic": "OFFICE CORRESPONDENCE : MEANING OF OFFICE CORRESPONDENCE", "question": "The Board of Directors of ABC & Co has just decided to reduce the workforce. The letter conveying this policy to the Managing Director for implementation would be marked", "images": [], "options": {"A": "official", "B": "confidential", "C": "urgent", "D": "personal"}, "answer": "B", "explanation": "When the Board of Directors of a company decides to reduce the workforce, the letter conveying this policy to the Managing Director for implementation would be marked as 'confidential'. This is because such information is sensitive and should only be known to those who need to know. Confidentiality is a set of rules or a promise that restricts access to or dissemination of information.", "marks": "1", "difficulty": "2"}, {"id": "objective>Office Practice>2021>22", "subject": "Office Practice", "year": "2021", "type": "Objective", "topic": "COMMUNICATION : METHODS/MEDIA OF COMMUNICATION", "question": "Which of the following means of written communications would an accountant use to convey a short directive to an accounts clerk?", "images": [], "options": {"A": "Circular", "B": "Report", "C": "Letter", "D": "Memorandum"}, "answer": "D", "explanation": "A memorandum, often shortened to memo, is a type of document used for internal communication between colleagues or members of a department within a company. It is used to convey information, and often directives, to employees. Therefore, an accountant would use a memorandum to convey a short directive to an accounts clerk.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2021>23", "subject": "Office Practice", "year": "2021", "type": "Objective", "topic": "MEETINGS : MEETING TERMINOLOGIES", "question": "When a meeting decides that a matter should lie on the table, it means that the matter should", "images": [], "options": {"A": "be discussed immediately", "B": "be discussed at the next meeting", "C": "not be discussed at all", "D": "be discussed at the executive level"}, "answer": "B", "explanation": "In the context of a meeting, when it is decided that a matter should 'lie on the table', it means that the matter is being temporarily set aside. The matter is not being dismissed entirely, but rather postponed for discussion at a later time, typically at the next meeting.", "marks": "1", "difficulty": "2"}, {"id": "objective>Office Practice>2021>24", "subject": "Office Practice", "year": "2021", "type": "Objective", "topic": "MAILS : PROCEDURES FOR HANDLING INCOMING AND OUTGOING MAILS", "question": "The section of an office in Rammy Ltd where mails are handled is", "images": [], "options": {"A": "registry", "B": "boardroom", "C": "reception", "D": "executive office"}, "answer": "A", "explanation": "The registry is the section of an office where mails are handled. It is responsible for the receipt, recording, distribution, storage, and disposal of mail in an organization. Therefore, in Rammy Ltd, mails would be handled in the registry.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2021>25", "subject": "Office Practice", "year": "2021", "type": "Objective", "topic": "COMMUNICATION : IMPORTANCE", "question": "Port Avenue & Co deals with lots of client. For the company receptionist to relate effectively with them, she would need to possess good", "images": [], "options": {"A": "communication skill", "B": "typing skill", "C": "filing skill", "D": "marketing skill"}, "answer": "A", "explanation": "A receptionist is the first point of contact for a company's clients. Therefore, they need to possess good communication skills to effectively interact with clients, understand their needs, and relay information accurately. While typing, filing, and marketing skills may be beneficial, communication is the most critical skill for a receptionist.", "marks": "1", "difficulty": "2"}, {"id": "objective>Office Practice>2021>26", "subject": "Office Practice", "year": "2021", "type": "Objective", "topic": "THE OFFICE : PRINCIPLES OF OFFICE", "question": "The principle Unity of Command in an office implies that", "images": [], "options": {"A": "no worker in an organization should report to more than one-line supervisior", "B": "every worker in an organization should be directly responsible to the general manager", "C": "everyone in the organization should be able to work in all departments", "D": "no worker in an organization should report to more than a two-line supervisor"}, "answer": "A", "explanation": "The principle of Unity of Command states that an employee should receive orders from one superior only. This prevents confusion and conflicts about how work should be done. It ensures clear lines of communication and responsibility. Therefore, the correct answer is that no worker in an organization should report to more than one-line supervisor.", "marks": "1", "difficulty": "2"}, {"id": "objective>Office Practice>2021>27", "subject": "Office Practice", "year": "2021", "type": "Objective", "topic": "MEETINGS : MEETING TERMINOLOGIES", "question": "What does it mean when a meeting is adjourned sine die ?", "images": [], "options": {"A": "There was no closing prayer", "B": "The meeting was fixed for another date", "C": "No date was fixed for its continuation", "D": "The meeting ended ended in chaos"}, "answer": "C", "explanation": "When a meeting is adjourned sine die, it means that it has been postponed indefinitely. The Latin term 'sine die' translates to 'without a day', meaning no date has been set for its continuation. Therefore, the correct answer is that no date was fixed for its continuation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Office Practice>2021>28", "subject": "Office Practice", "year": "2021", "type": "Objective", "topic": "DEPARTMENTS IN AN ORGANIZATION : FUNCTIONS OF EACH DEPARTMENT", "question": "At Adesco Plc, Mr Jack is the one who assgins duties to all the office workers. Mr.Jack is acting as the", "images": [], "options": {"A": "Secretary", "B": "Manager", "C": "Director", "D": "Receptionist"}, "answer": "B", "explanation": "In a company, the person who assigns duties to all the office workers is typically the Manager. The manager is responsible for planning, directing, and overseeing the operations and fiscal health of a business unit, division, department, or an operating unit within an organization. The manager is also responsible for delegating and directing tasks and operations to employees, managing performance and project goals, providing constructive feedback, and resolving team issues.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2021>29", "subject": "Office Practice", "year": "2021", "type": "Objective", "topic": "THE RECEPTION : DOCUMENTS HANDLED BY A RECEPTIONIST", "question": "Which of these items could be found in the reception?", "images": [], "options": {"A": "Inward and outward registers", "B": "Attendance registers", "C": "Newspaper and Magazine", "D": "Dispatch book"}, "answer": "C", "explanation": "In the reception area of an office, you are likely to find items like newspapers and magazines. These are usually provided for visitors to read while they wait for their appointments. The other options listed such as inward and outward registers, attendance registers, and dispatch books are typically not found in the reception area, but rather in other parts of the office.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2021>30", "subject": "Office Practice", "year": "2021", "type": "Objective", "topic": "MEETINGS : PURPOSE", "question": "The purpose of a notice of meeting is to inform members of the", "images": [], "options": {"A": "time, date and venue of a proposed meeting", "B": "decision taken at the previous meeting", "C": "postponement of a proposed meeting", "D": "items to be discussed at the meeting"}, "answer": "A", "explanation": "The purpose of a notice of meeting is to inform members of the time, date, and venue of a proposed meeting. This allows members to plan their schedules accordingly and ensures that they are aware of when and where the meeting will take place. The other options listed such as decisions taken at the previous meeting, postponement of a proposed meeting, and items to be discussed at the meeting are typically included in the agenda or minutes of the meeting, not the notice.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2021>31", "subject": "Office Practice", "year": "2021", "type": "Objective", "topic": "THE OFFICE : PRINCIPLES OF OFFICE", "question": "The principles of office organization which requires workers to be assigned duties according to their skills and qualifications is", "images": [], "options": {"A": "delegation of authority", "B": "flexibility", "C": "specialization", "D": "unity of control"}, "answer": "C", "explanation": "The principle of office organization that requires workers to be assigned duties according to their skills and qualifications is 'specialization'. Specialization refers to the concept of focusing on a specific area or task, allowing individuals to hone their skills in that particular area, leading to increased efficiency and productivity.", "marks": "1", "difficulty": "2"}, {"id": "objective>Office Practice>2021>32", "subject": "Office Practice", "year": "2021", "type": "Objective", "topic": "MAILS : PROCEDURES FOR HANDLING INCOMING AND OUTGOING MAILS", "question": "Which of the following activties does the handling of incoming mails involve?", "images": [], "options": {"A": "Addressing the envelope", "B": "Enveloping the document", "C": "Examining the content", "D": "Dispatching the mail"}, "answer": "C", "explanation": "The handling of incoming mails involves 'Examining the content'. This is a crucial step in the process of handling incoming mail, as it allows the recipient to understand the purpose of the mail and take appropriate action. The other options listed are not typically involved in the handling of incoming mail.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2021>33", "subject": "Office Practice", "year": "2021", "type": "Objective", "topic": "THE OFFICE : LAYOUT OF AN OFFICE", "question": "In a closed office layout, workers enjoy", "images": [], "options": {"A": "better supervision", "B": "better rapport", "C": "relative comfort", "D": "swift flow of work"}, "answer": "C", "explanation": "In a closed office layout, workers enjoy 'relative comfort'. A closed office layout refers to a workspace design where each employee has their own individual office space. This can provide a more comfortable work environment as it offers more privacy and less noise compared to an open office layout. The other options listed may not necessarily be true in a closed office layout.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2021>34", "subject": "Office Practice", "year": "2021", "type": "Objective", "topic": "OFFICE CORRESPONDENCE : MEANING OF OFFICE CORRESPONDENCE", "question": "A letter from Mr Jack to convince XYZ company to employ Miss Zizi is", "images": [], "options": {"A": "a recommendation letter", "B": "an order letter", "C": "a letter of request", "D": "a letter of appointment"}, "answer": "A", "explanation": "A letter from Mr Jack to convince XYZ company to employ Miss Zizi is a recommendation letter. A recommendation letter is a document in which the writer assesses the qualities, characteristics, and capabilities of the person being recommended in terms of that individual's ability to perform a particular task or function. In this case, Mr Jack is recommending Miss Zizi for employment.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2021>35", "subject": "Office Practice", "year": "2021", "type": "Objective", "topic": "DEPARTMENTS IN AN ORGANIZATION : FUNCTIONS OF EACH DEPARTMENT", "question": "The department in an organization that monitors the implementation of a company's policies is", "images": [], "options": {"A": "finance department", "B": "marketing department", "C": "administrative department", "D": "research and development department"}, "answer": "C", "explanation": "The administrative department in an organization is responsible for monitoring the implementation of a company's policies. The administrative department is responsible for the day-to-day operations of the company, including enforcing company policies and procedures.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2021>36", "subject": "Office Practice", "year": "2021", "type": "Objective", "topic": "THE RECEPTION : DUTIES", "question": "A receptionist is an employee who", "images": [], "options": {"A": "directs visitors to the office they wants to see", "B": "operates varieties of equipment in the office", "C": "supervises the junior employees in the office", "D": "prepares itineraries for his superior officers"}, "answer": "A", "explanation": "A receptionist is an employee who directs visitors to the office they want to see. The receptionist is often the first point of contact for clients and visitors, and their role includes directing visitors to the appropriate office or person.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2021>37", "subject": "Office Practice", "year": "2021", "type": "Objective", "topic": "COMMUNICATION : METHODS/MEDIA OF COMMUNICATION", "question": "Communication to a large number of people in different locations simultaneously could be done by means of", "images": [], "options": {"A": "telephone", "B": "advertisement", "C": "merchandizing", "D": "display"}, "answer": "B", "explanation": "Communication to a large number of people in different locations simultaneously is best done through advertisements. Advertisements can be broadcasted or published across various platforms (TV, radio, internet, print media etc.) reaching a large audience at the same time. The other options like telephone, merchandizing, and display are not as effective for simultaneous communication to a large audience in different locations.", "marks": "1", "difficulty": "2"}, {"id": "objective>Office Practice>2021>38", "subject": "Office Practice", "year": "2021", "type": "Objective", "topic": "INFORMATION : USES", "question": "During a recent workshop, participants were advised to always provide good information. In order words, any information given by them should be", "images": [], "options": {"A": "timely", "B": "futuristic", "C": "long", "D": "short"}, "answer": "A", "explanation": "Good information should be timely. This means it should be provided at the right time or when it is needed. Timely information helps in making accurate and effective decisions. Futuristic, long, or short does not necessarily define good information. Information can be long or short, but if it's not timely, it may not be useful.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2021>39", "subject": "Office Practice", "year": "2021", "type": "Objective", "topic": "OFFICE EQUIPMENT : MEANING OF OFFICE EQUIPMENT", "question": "Which of these factors would a purchasing officer consider in selecting an office equipment?", "images": [], "options": {"A": "Control", "B": "Location", "C": "Suitability", "D": "Colour"}, "answer": "C", "explanation": "In selecting an office equipment, a purchasing officer would consider its suitability. This means whether the equipment is appropriate or fit for the intended purpose or use in the office. Control, location, and colour are not primary factors in selecting office equipment. The functionality and suitability of the equipment for the office tasks are more important.", "marks": "1", "difficulty": "2"}, {"id": "objective>Office Practice>2021>40", "subject": "Office Practice", "year": "2021", "type": "Objective", "topic": "MAILS : PROCEDURES FOR HANDLING INCOMING AND OUTGOING MAILS", "question": "Which of the following activities is part of the procedure for handling outgoing mails?", "images": [], "options": {"A": "Stamping", "B": "Coding", "C": "Opening", "D": "Sorting"}, "answer": "A", "explanation": "Stamping is part of the procedure for handling outgoing mails. It involves affixing postage stamps to the mail to indicate that the postage fee has been paid. Coding, opening, and sorting are typically associated with incoming mail, not outgoing mail.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2021>41", "subject": "Office Practice", "year": "2021", "type": "Objective", "topic": "OFFICE EQUIPMENT : TYPES OF OFFICE EQUIPMENT", "question": "Bodex co.Ltd sends out lots of mails. Which of the following office machines would help to remove the burden of affixing postage stamps on each envelope?", "images": [], "options": {"A": "Collating machine", "B": "Addressing machine", "C": "Franking machine", "D": "Folding machine"}, "answer": "C", "explanation": "A franking machine is used to print a postage mark directly onto envelopes or labels, which can then be affixed to mail. This removes the need to manually affix postage stamps to each envelope, making it an ideal solution for a company like Bodex co.Ltd that sends out lots of mails. Collating machines, addressing machines, and folding machines perform different functions and would not help with this task.", "marks": "1", "difficulty": "2"}, {"id": "objective>Office Practice>2021>42", "subject": "Office Practice", "year": "2021", "type": "Objective", "topic": "OFFICE DOCUMENTS : USES", "question": "Which of these documents would be used to procure an item from the store?", "images": [], "options": {"A": "Quotation", "B": "Receipt", "C": "Invoice", "D": "Requisition"}, "answer": "D", "explanation": "A requisition is a formal request to procure an item from the store. It is typically used in business settings to request that specific goods be ordered. A quotation is a document that states a price for goods or services, an invoice is a bill for goods or services provided, and a receipt is a document acknowledging that a person has received money or property in payment.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2021>43", "subject": "Office Practice", "year": "2021", "type": "Objective", "topic": "COMMUNICATION : METHODS/MEDIA OF COMMUNICATION", "question": "A form of correspondence used in conveying information to members of the public is", "images": [], "options": {"A": "press release", "B": "endorsement", "C": "briefs", "D": "circular"}, "answer": "A", "explanation": "A press release is a form of correspondence used to convey information to members of the public. It is a written communication that reports specific but brief information about an event, circumstance, or other happening. It's typically tied to a business or organization and is provided to media through a variety of means.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2021>44", "subject": "Office Practice", "year": "2021", "type": "Objective", "topic": "MEETINGS : TYPES", "question": "A group of people appointed by the parent committee to deal with a special matter is", "images": [], "options": {"A": "standing committee", "B": "ad hoc committee", "C": "executive committee", "D": "joint action committee"}, "answer": "B", "explanation": "An ad hoc committee is a group of people appointed by the parent committee to deal with a special matter. The term 'ad hoc' is a Latin phrase that literally means 'for this', implying created or done for a particular purpose as necessary. The committee is usually disbanded after the task is completed.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2021>45", "subject": "Office Practice", "year": "2021", "type": "Objective", "topic": "COMMUNICATION : DEFINITION OF COMMUNICATION", "question": "A secretary has found it difficult to type a manuscript given to her by the manager due to poor handwriting. In other words, the secretary has the challenge of", "images": [], "options": {"A": "inability to encode the manuscript", "B": "poor encoded manuscript by the manager", "C": "poorly decoded manuscript by the manager", "D": "inappropriate choice of channel"}, "answer": "B", "explanation": "The secretary is having difficulty typing the manuscript due to poor handwriting. This means the manuscript was poorly encoded by the manager. Encoding in this context refers to the process of putting thoughts into symbols for communication, which in this case is the manager's handwriting.", "marks": "1", "difficulty": "2"}, {"id": "objective>Office Practice>2021>46", "subject": "Office Practice", "year": "2021", "type": "Objective", "topic": "OFFICE EQUIPMENT : TYPES OF OFFICE EQUIPMENT", "question": "At Zeinab & Sons Plc, envelopes are fastened with the use of gum and this takes so much time. The machine which would help overcome this challenge is", "images": [], "options": {"A": "collating machine", "B": "folding machine", "C": "sealing machine", "D": "jogging machine"}, "answer": "C", "explanation": "A sealing machine is used to seal envelopes, which would speed up the process at Zeinab & Sons Plc. A collating machine is used to arrange papers in a specific order, a folding machine is used to fold papers, and a jogging machine is used to align stacks of paper - none of these would help with sealing envelopes.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2021>47", "subject": "Office Practice", "year": "2021", "type": "Objective", "topic": "MAILS : TYPES OF MAILS", "question": "A letter containing valuable documents would be sent by", "images": [], "options": {"A": "electronic mail", "B": "surface handling", "C": "registered mail", "D": "airmail"}, "answer": "C", "explanation": "Registered mail is a mail service offered by postal services in many countries, which allows the sender proof of mailing via a mailing receipt and, upon request, electronic verification that an article was delivered or that a delivery attempt was made. This makes it the most secure way to send a letter containing valuable documents. Electronic mail wouldn't be suitable for physical documents, and surface handling and airmail don't provide the same level of security.", "marks": "1", "difficulty": "2"}, {"id": "objective>Office Practice>2021>48", "subject": "Office Practice", "year": "2021", "type": "Objective", "topic": "COMMUNICATION : DEFINITION OF COMMUNICATION", "question": "In communication process, writing a memo is an example of", "images": [], "options": {"A": "decoding", "B": "feedback", "C": "encoding", "D": "channel"}, "answer": "C", "explanation": "In the communication process, writing a memo is an example of encoding. Encoding is the process of turning thoughts into communication. The encoder uses a 'medium' to send the message -- a phone call, email, text message, face-to-face meeting, or other communication tool. The level of conscious thought that goes into encoding messages depends on the individual.", "marks": "1", "difficulty": "2"}, {"id": "objective>Office Practice>2021>49", "subject": "Office Practice", "year": "2021", "type": "Objective", "topic": "DEPARTMENTS IN AN ORGANIZATION : ORGANIZATIONAL CHART", "question": "Which of these organizational structures is also referred to as military form of organization?", "images": [], "options": {"A": "Functional", "B": "Line", "C": "Line and staff", "D": "Committee"}, "answer": "B", "explanation": "The Line organizational structure is also referred to as the military form of organization. This is because, in this structure, authority flows vertically from top to bottom with clear lines of command and control, similar to the military.", "marks": "1", "difficulty": "2"}, {"id": "objective>Office Practice>2021>50", "subject": "Office Practice", "year": "2021", "type": "Objective", "topic": "OFFICE CORRESPONDENCE : MEANING OF OFFICE CORRESPONDENCE", "question": "A document sent by the buyer to the seller when the goods supplied are not satisfactory is", "images": [], "options": {"A": "a letter of complaints", "B": "an order", "C": "a quotation letter", "D": "a letter of enquiry"}, "answer": "A", "explanation": "When the goods supplied are not satisfactory, the buyer sends a letter of complaints to the seller. This letter is used to express dissatisfaction for a product or service and to request for a remedy, which could be a refund, replacement, or repair of the goods.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2025>1", "subject": "Office Practice", "year": "2025", "type": "Objective", "topic": "MEETINGS : TYPES", "question": "The appointment of a  new Managing Director during a meeting must have been one of the items on the", "images": [], "options": {"A": "programme", "B": "manifest", "C": "itinerary", "D": "agenda"}, "answer": "D", "explanation": "The correct term for a list of items to be discussed in a meeting is 'agenda'. An agenda outlines the topics and order of business for the meeting, making it essential for organizing discussions.", "marks": "1", "difficulty": "2"}, {"id": "objective>Office Practice>2025>2", "subject": "Office Practice", "year": "2025", "type": "Objective", "topic": "THE RECEPTION : DUTIES", "question": "One of the qualities of a receptionist that enables her to treat visitors with care and wisdom is", "images": [], "options": {"A": "appearance", "B": "fluency", "C": "tactfulness", "D": "loyalty"}, "answer": "C", "explanation": "Tactfulness is the quality that allows a receptionist to handle visitors with care and wisdom. It involves sensitivity in dealing with others, especially in difficult situations, which is crucial for a receptionist's role.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2025>3", "subject": "Office Practice", "year": "2025", "type": "Objective", "topic": "OFFICE EQUIPMENT : TYPES OF OFFICE EQUIPMENT", "question": "The device used to monitor productivity and manage employee's work hours is", "images": [], "options": {"A": "job card", "B": "punch card", "C": "clock card", "D": "card index"}, "answer": "B", "explanation": "A punch card is a device used to record the time an employee starts and ends their work. It helps in monitoring productivity and managing work hours by providing a physical record of attendance.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2025>4", "subject": "Office Practice", "year": "2025", "type": "Objective", "topic": "OFFICE DOCUMENTS : TYPES", "question": "The document that serves as evidence of payment for goods and services is", "images": [], "options": {"A": "invoice", "B": "receipt", "C": "credit note", "D": "debit note"}, "answer": "B", "explanation": "A receipt is a document that serves as evidence of payment for goods and services. It confirms that a transaction has taken place and is often required for returns or warranty claims.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2025>5", "subject": "Office Practice", "year": "2025", "type": "Objective", "topic": "MEETINGS : TYPES", "question": "A meeting which all companies are required by law to hold one in a year is", "images": [], "options": {"A": "staff meeting", "B": "board meeting", "C": "annual general meeting", "D": "extraordinary general meeting"}, "answer": "C", "explanation": "An annual general meeting (AGM) is a mandatory yearly gathering of a company's stakeholders. During the AGM, the directors present the company's annual report, and shareholders have the opportunity to ask questions and vote on important issues.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2025>6", "subject": "Office Practice", "year": "2025", "type": "Objective", "topic": "OFFICE EQUIPMENT : TYPES OF OFFICE EQUIPMENT", "question": "A machine that could be used in printing postage impression on envelopes before despatching is", "images": [], "options": {"A": "date stamping machine", "B": "franking machine", "C": "binding machine", "D": "jogging machine"}, "answer": "B", "explanation": "The correct answer is 'franking machine'. A franking machine is specifically designed to print postage impressions on envelopes, allowing businesses to send mail without needing to use traditional postage stamps.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2025>7", "subject": "Office Practice", "year": "2025", "type": "Objective", "topic": "INFORMATION : STORAGE OF INFORMATION", "question": "An example of information storage device is", "images": [], "options": {"A": "light pen", "B": "printer", "C": "magnetic tape", "D": "monitor"}, "answer": "C", "explanation": "The correct answer is 'magnetic tape'. A magnetic tape is a data storage device that uses magnetic storage to record and retrieve digital information, making it a classic example of an information storage device.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2025>8", "subject": "Office Practice", "year": "2025", "type": "Objective", "topic": "COMMUNICATION : METHODS/MEDIA OF COMMUNICATION", "question": "The use of a loudspeaker to pass information across to an audience is an example of", "images": [], "options": {"A": "oral communication", "B": "non-verbal communication", "C": "visual communication", "D": "audio-visual communication"}, "answer": "A", "explanation": "The correct answer is 'oral communication'. Using a loudspeaker to convey information to an audience is a form of oral communication, as it involves spoken words being transmitted to listeners.", "marks": "1", "difficulty": "2"}, {"id": "objective>Office Practice>2025>9", "subject": "Office Practice", "year": "2025", "type": "Objective", "topic": "OFFICE EQUIPMENT : MEANING OF OFFICE EQUIPMENT", "question": "Use the following information to answer the question    Chief Tom bought some electronic equipment at #120,000 from Gabby Electronics Ltd. He instructed his bank to pay Gabby Electronics an equal installment every month for six months.    The method of payment adopted by Chief Tom is", "images": [], "options": {"A": "bank draft", "B": "credit transfer", "C": "direct debit", "D": "standing order"}, "answer": "C", "explanation": "The correct answer is 'direct debit'. In this scenario, Chief Tom instructs his bank to make regular payments to Gabby Electronics, which is characteristic of a direct debit arrangement where the bank automatically transfers funds from his account to the recipient.", "marks": "1", "difficulty": "2"}, {"id": "objective>Office Practice>2025>10", "subject": "Office Practice", "year": "2025", "type": "Objective", "topic": "OFFICE EQUIPMENT : MEANING OF OFFICE EQUIPMENT", "question": "Use the following information to answer the question    Chief Tom bought some electronic equipment at #120,000 from Gabby Electronics Ltd. He instructed his bank to pay Gabby Electronics an equal installment every month for six months.    How much would the bank be paying to Gabby Electronics Ltd every month?", "images": [], "options": {"A": "#20,000", "B": "#15,000", "C": "#12,000", "D": "#10,000"}, "answer": "A", "explanation": "The correct answer is '#20,000'. Chief Tom is paying a total of #120,000 over six months, which means the monthly payment is calculated as #120,000 divided by 6, resulting in #20,000 per month.", "marks": "1", "difficulty": "2"}, {"id": "objective>Office Practice>2025>11", "subject": "Office Practice", "year": "2025", "type": "Objective", "topic": "MEETINGS : MEETING TERMINOLOGIES", "question": "A formal suggestion put before a meeting for consideration is a", "images": [], "options": {"A": "proposal", "B": "decision", "C": "resolution", "D": "request"}, "answer": "A", "explanation": "A formal suggestion put before a meeting for consideration is called a 'proposal'. A proposal outlines a plan or suggestion for consideration and discussion, making it the correct term in this context.", "marks": "1", "difficulty": "2"}, {"id": "objective>Office Practice>2025>12", "subject": "Office Practice", "year": "2025", "type": "Objective", "topic": "MAILS : PROCEDURES FOR HANDLING INCOMING AND OUTGOING MAILS", "question": "The date-stamp on an incoming mail shows the", "images": [], "options": {"A": "day the mail was received", "B": "time the mail was received", "C": "name of the officer who received the mail", "D": "day and time the mail was delivered"}, "answer": "A", "explanation": "The date-stamp on an incoming mail shows the 'day the mail was received'. This is a standard practice in mail handling to track when correspondence arrives.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2025>13", "subject": "Office Practice", "year": "2025", "type": "Objective", "topic": "OFFICE CORRESPONDENCE : TYPES", "question": "The part of a business letter that would easily help the mail clerk to know the officer who would handle it is the", "images": [], "options": {"A": "salutation", "B": "reference", "C": "attention line", "D": "complimenary close"}, "answer": "C", "explanation": "The part of a business letter that helps the mail clerk identify the officer who would handle it is the 'attention line'. This line directs the letter to a specific person or department, facilitating proper handling.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2025>14", "subject": "Office Practice", "year": "2025", "type": "Objective", "topic": "MAILS : TYPES OF MAILS", "question": "A&B Company needs to send a letter to XY Company that must be delivered within a given period. Which of these communication services would be suitable for instant delivery?", "images": [], "options": {"A": "Postal service", "B": "Courier service", "C": "SMS", "D": "E-mail"}, "answer": "B", "explanation": "For instant delivery, a 'Courier service' is the most suitable option. Unlike postal services, which can take longer, courier services are designed for quick and reliable delivery of documents and packages.", "marks": "1", "difficulty": "2"}, {"id": "objective>Office Practice>2025>15", "subject": "Office Practice", "year": "2025", "type": "Objective", "topic": "REPORT WRITINGS : PARTS OF A REPORT", "question": "Attachments to a report for further clarification are", "images": [], "options": {"A": "recommendations", "B": "appendices", "C": "references", "D": "bibliographic"}, "answer": "B", "explanation": "Attachments to a report for further clarification are known as 'appendices'. Appendices provide additional information that supports the main content of the report, making them essential for comprehensive understanding.", "marks": "1", "difficulty": "2"}, {"id": "objective>Office Practice>2025>16", "subject": "Office Practice", "year": "2025", "type": "Objective", "topic": "OFFICE EQUIPMENT : TYPES OF OFFICE EQUIPMENT", "question": "Reprographics are handled in the office by the", "images": [], "options": {"A": "receptionist", "B": "clerical officer", "C": "supervisor", "D": "general manager"}, "answer": "B", "explanation": "Reprographics, which involves the reproduction of documents and images, is typically handled by clerical officers in an office setting. They are responsible for tasks such as copying, printing, and managing documents.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2025>17", "subject": "Office Practice", "year": "2025", "type": "Objective", "topic": "DEPARTMENTS IN AN ORGANIZATION : FUNCTIONS OF EACH DEPARTMENT", "question": "The principle that states that every staff in an organization should be accountable to one supervisor is", "images": [], "options": {"A": "level of management", "B": "unity of command", "C": "unity of objective", "D": "delegation of authority"}, "answer": "B", "explanation": "The principle of 'unity of command' states that each employee should report to only one supervisor to avoid confusion and conflicting instructions. This principle helps maintain clear lines of authority and accountability within an organization.", "marks": "1", "difficulty": "2"}, {"id": "objective>Office Practice>2025>18", "subject": "Office Practice", "year": "2025", "type": "Objective", "topic": "REPORT WRITINGS : MEANING OR REPORT WRITING", "question": "An advantage of report writing to an organization is that it", "images": [], "options": {"A": "helps in solving organizational problem", "B": "enhances the image of the organization", "C": "is used as part of communication skills", "D": "adds to the document of the organization"}, "answer": "A", "explanation": "Report writing helps in solving organizational problems by providing a structured way to present information, analyze issues, and propose solutions. It serves as a formal method of communication that can enhance decision-making processes.", "marks": "1", "difficulty": "2"}, {"id": "objective>Office Practice>2025>19", "subject": "Office Practice", "year": "2025", "type": "Objective", "topic": "OFFICE EQUIPMENT : TYPES OF OFFICE EQUIPMENT", "question": "Which of these computer devices displays data?", "images": [], "options": {"A": "Monitor", "B": "Scanner", "C": "Diskette", "D": "Joystick"}, "answer": "A", "explanation": "A monitor is a computer device that displays data visually. It is an output device that presents information processed by the computer in a format that can be easily understood by users.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2025>20", "subject": "Office Practice", "year": "2025", "type": "Objective", "topic": "OFFICE EQUIPMENT : MEANING OF OFFICE EQUIPMENT", "question": "An electronic device capable of accepting data through input devices and processes is  a", "images": [], "options": {"A": "photocopier", "B": "scanner", "C": "computer", "D": "shredder"}, "answer": "C", "explanation": "A computer is an electronic device that accepts data through input devices (like a keyboard or mouse), processes that data, and produces output. It is capable of performing a wide range of tasks based on the instructions provided by software.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2025>21", "subject": "Office Practice", "year": "2025", "type": "Objective", "topic": "COMMUNICATION : METHODS/MEDIA OF COMMUNICATION", "question": "A supervisor issued a query letter to an erring subordinate in an office. The means of communication used is", "images": [], "options": {"A": "written", "B": "oral", "C": "visual", "D": "audio"}, "answer": "A", "explanation": "The correct means of communication used by a supervisor to issue a query letter to a subordinate is 'written'. Written communication is formal and provides a record of the communication, which is essential in a professional setting.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2025>22", "subject": "Office Practice", "year": "2025", "type": "Objective", "topic": "OFFICE DOCUMENTS : MEANING OF OFFICE DOCUMENT", "question": "The subject headings of a business letter is written", "images": [], "options": {"A": "after the body of the letter", "B": "before the attention line", "C": "after the salutation", "D": "before the reference"}, "answer": "D", "explanation": "In a business letter, the subject heading is typically written before the reference. This placement helps to clearly indicate the purpose of the letter to the recipient right at the beginning.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2025>23", "subject": "Office Practice", "year": "2025", "type": "Objective", "topic": "THE OFFICE : FUNCTIONS OF OFFICE", "question": "A central place in an organization where clerical work are carried out is the", "images": [], "options": {"A": "meeting room", "B": "waiting room", "C": "office", "D": "registry"}, "answer": "C", "explanation": "The central place in an organization where clerical work is carried out is referred to as the 'office'. An office is designed to facilitate administrative tasks and support the overall operations of the organization.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2025>24", "subject": "Office Practice", "year": "2025", "type": "Objective", "topic": "FILING : SYSTEMS OF FILING", "question": "Which of these features should be considered when taking decision on filing system to be used in an organization?", "images": [], "options": {"A": "Accessibility", "B": "Uniformity", "C": "Objectivity", "D": "Systematic"}, "answer": "A", "explanation": "When deciding on a filing system for an organization, 'Accessibility' is a crucial feature. A filing system should allow easy access to documents for efficiency and productivity, ensuring that employees can retrieve information quickly.", "marks": "1", "difficulty": "2"}, {"id": "objective>Office Practice>2025>25", "subject": "Office Practice", "year": "2025", "type": "Objective", "topic": "THE RECEPTION : DUTIES", "question": "Canbell, the receptionist of O&X Company Ltd, received different categories of visitors into the organization. Which of the following categories of visitors should be given priorities?", "images": [], "options": {"A": "Visitors with appointment", "B": "Emergency visitors", "C": "Regular visitors", "D": "Casual visitors"}, "answer": "B", "explanation": "Emergency visitors should be given priority as they may require immediate attention or assistance. This prioritization is essential in ensuring the safety and well-being of individuals in urgent situations.", "marks": "1", "difficulty": "2"}, {"id": "objective>Office Practice>2025>26", "subject": "Office Practice", "year": "2025", "type": "Objective", "topic": "MEETINGS : TYPES", "question": "Which of these committees would be dissolved as soon as its assignment is completed?", "images": [], "options": {"A": "Joint committee", "B": "Ad-hoc committee", "C": "Standing committee", "D": "Executive committee"}, "answer": "B", "explanation": "An Ad-hoc committee is formed for a specific task or purpose and is dissolved once that task is completed. This distinguishes it from other types of committees, such as Joint, Standing, and Executive committees, which are typically ongoing or have broader responsibilities.", "marks": "1", "difficulty": "2"}, {"id": "objective>Office Practice>2025>27", "subject": "Office Practice", "year": "2025", "type": "Objective", "topic": "DEPARTMENTS IN AN ORGANIZATION : FUNCTIONS OF EACH DEPARTMENT", "question": "The department that is responsible for making recommendations on the purchase of new vehicles is", "images": [], "options": {"A": "marketing", "B": "production", "C": "accounts", "D": "administration"}, "answer": "D", "explanation": "The administration department is generally responsible for making recommendations on the purchase of new vehicles, as it oversees the operational needs and logistics of the organization, including fleet management.", "marks": "1", "difficulty": "2"}, {"id": "objective>Office Practice>2025>28", "subject": "Office Practice", "year": "2025", "type": "Objective", "topic": "FILING : CLASSIFICATION OF FILING", "question": "In alphabetical order of filing, the first unit of filing is the", "images": [], "options": {"A": "surname", "B": "middle name", "C": "first name", "D": "title"}, "answer": "C", "explanation": "In alphabetical order of filing, the first unit of filing is the first name. This is because filing systems typically prioritize the first name over the surname or middle name when organizing names alphabetically.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2025>29", "subject": "Office Practice", "year": "2025", "type": "Objective", "topic": "OFFICE DOCUMENTS : MEANING OF OFFICE DOCUMENT", "question": "In a business letter, the space immediately after the complimentary close is for the", "images": [], "options": {"A": "signature of the officer", "B": "name of the officer", "C": "designation of the officer", "D": "name of the organization"}, "answer": "B", "explanation": "In a business letter, the space immediately after the complimentary close is reserved for the name of the officer who is signing the letter. This is important for identifying the individual responsible for the correspondence.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2025>30", "subject": "Office Practice", "year": "2025", "type": "Objective", "topic": "COMMUNICATION : METHODS/MEDIA OF COMMUNICATION", "question": "Which of these means of communication is used by kings to pass important information to the community?", "images": [], "options": {"A": "Town crier", "B": "Buzzer", "C": "Whistle", "D": "Symbol"}, "answer": "A", "explanation": "A Town crier was historically used to announce important news and information to the community, serving as a means of communication before the advent of modern media. This role was crucial for disseminating information in a time when literacy rates were low.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2025>31", "subject": "Office Practice", "year": "2025", "type": "Objective", "topic": "DEPARTMENTS IN AN ORGANIZATION : FUNCTIONS OF EACH DEPARTMENT", "question": "In an organization, advertisement unit is under", "images": [], "options": {"A": "marketing department", "B": "human resources department", "C": "production department", "D": "accounts department"}, "answer": "A", "explanation": "In an organization, the advertisement unit typically falls under the marketing department, as marketing is responsible for promoting products and services, which includes advertising.", "marks": "1", "difficulty": "2"}, {"id": "objective>Office Practice>2025>32", "subject": "Office Practice", "year": "2025", "type": "Objective", "topic": "REPORT WRITINGS : MEANING OR REPORT WRITING", "question": "Chucks is a daily-paid worker at RD Ltd. Each time he completes his work earlier than the time allocated, he would be paid his normal daily rate plus extra amount for saving  time. Which system of payment is used for paying Chucks?", "images": [], "options": {"A": "Time rate", "B": "Premium bonus", "C": "Profit sharing", "D": "Commission"}, "answer": "B", "explanation": "Chucks is being paid a normal daily rate plus an extra amount for saving time, which indicates a premium bonus system. This system rewards employees for exceeding performance expectations, such as completing work ahead of schedule.", "marks": "1", "difficulty": "2"}, {"id": "objective>Office Practice>2025>33", "subject": "Office Practice", "year": "2025", "type": "Objective", "topic": "COMMUNICATION : METHODS/MEDIA OF COMMUNICATION", "question": "One of the advantages of visual communication is that", "images": [], "options": {"A": "tension can arise as to what to say", "B": "one can be easily misquoted", "C": "it elicits quick response", "D": "it lacks human feeling"}, "answer": "C", "explanation": "One of the advantages of visual communication is that it elicits quick responses. Visuals can convey information rapidly and clearly, making it easier for the audience to understand and react promptly.", "marks": "1", "difficulty": "2"}, {"id": "objective>Office Practice>2025>34", "subject": "Office Practice", "year": "2025", "type": "Objective", "topic": "MEETINGS : TYPES", "question": "The heads of department XZee Company Ltd held a meeting to take decisions on major issues in the company. After the meeting, each head of department was mandated to call the employees under them and brief them about the decision taken. The meeting of heads of department is", "images": [], "options": {"A": "a management meeting", "B": "a committee meeting", "C": "an emergency meeting", "D": "a general meeting"}, "answer": "A", "explanation": "The meeting of heads of department is classified as a management meeting, as it involves decision-making at a managerial level regarding major issues within the company.", "marks": "1", "difficulty": "2"}, {"id": "objective>Office Practice>2025>35", "subject": "Office Practice", "year": "2025", "type": "Objective", "topic": "OFFICE CORRESPONDENCE : TYPES", "question": "Which of these parts of letter is common ot both a business letter and a memo?", "images": [], "options": {"A": "Two addresses", "B": "Salutation", "C": "Subject heading", "D": "Complimentary close"}, "answer": "C", "explanation": "The subject heading is a common part of both a business letter and a memo. It serves to indicate the topic of the communication, making it easier for the recipient to understand the purpose of the document.", "marks": "1", "difficulty": "2"}, {"id": "objective>Office Practice>2025>36", "subject": "Office Practice", "year": "2025", "type": "Objective", "topic": "MAILS : PROCEDURES FOR HANDLING INCOMING AND OUTGOING MAILS", "question": "If an enclosure indicated in a mail is missing, the mail clerk should", "images": [], "options": {"A": "inform the sender immediately", "B": "make a note to that effect", "C": "ask the deliverer to take the mail back", "D": "call the post office and report about it"}, "answer": "A", "explanation": "If an enclosure indicated in a mail is missing, the mail clerk should inform the sender immediately. This is important to ensure that the sender is aware of the issue and can take appropriate action, such as resending the missing documents.", "marks": "1", "difficulty": "2"}, {"id": "objective>Office Practice>2025>37", "subject": "Office Practice", "year": "2025", "type": "Objective", "topic": "OFFICE DOCUMENTS : TYPES", "question": "When goods are undercharged by a  seller, the document to be sent to the buyer is a", "images": [], "options": {"A": "debit note", "B": "statement of account", "C": "credit note", "D": "proforma invoice"}, "answer": "A", "explanation": "When goods are undercharged by a seller, the appropriate document to send to the buyer is a debit note. A debit note is used to formally request payment for the undercharged amount, indicating that the buyer owes more than what was initially billed.", "marks": "1", "difficulty": "2"}, {"id": "objective>Office Practice>2025>38", "subject": "Office Practice", "year": "2025", "type": "Objective", "topic": "FILING : CLASSIFICATION OF FILING", "question": "The process of storing records by photographing them in a miniature form is", "images": [], "options": {"A": "microfilming", "B": "magnetic taping", "C": "microfiche", "D": "projecting"}, "answer": "A", "explanation": "The process of storing records by photographing them in a miniature form is known as microfilming. This technique allows for the preservation of documents in a compact format, making it easier to store and retrieve large volumes of information.", "marks": "1", "difficulty": "2"}, {"id": "objective>Office Practice>2025>39", "subject": "Office Practice", "year": "2025", "type": "Objective", "topic": "DEPARTMENTS IN AN ORGANIZATION : ORGANIZATIONAL CHART", "question": "The organizational structure in which an officer supervises his specialized area is", "images": [], "options": {"A": "functional", "B": "matrix", "C": "committee", "D": "staff"}, "answer": "A", "explanation": "The organizational structure in which an officer supervises his specialized area is called functional structure. In this type of structure, employees are grouped based on their specialized roles or functions, allowing for greater efficiency and expertise in specific areas.", "marks": "1", "difficulty": "2"}, {"id": "objective>Office Practice>2025>40", "subject": "Office Practice", "year": "2025", "type": "Objective", "topic": "FILING : CLASSIFICATION OF FILING", "question": "Aisha Ventures has clients in Lagos, Abuja, Enugu and Port Harcourt. Which of the filing classification is most suitable for the firm?", "images": [], "options": {"A": "Alphabetical filing", "B": "Numerical filing", "C": "Geographical filing", "D": "Subject filing"}, "answer": "C", "explanation": "For Aisha Ventures, which has clients in multiple cities, the most suitable filing classification is geographical filing. This method organizes files based on geographic locations, making it easier to access client information based on their respective areas.", "marks": "1", "difficulty": "2"}, {"id": "objective>Office Practice>2025>41", "subject": "Office Practice", "year": "2025", "type": "Objective", "topic": "OFFICE CORRESPONDENCE : TYPES", "question": "A supervisor who wishes to write to the subordinate on incessant lateness to work would use a", "images": [], "options": {"A": "memo", "B": "letter", "C": "bulletin", "D": "circular"}, "answer": "A", "explanation": "A memo is typically used for internal communication within an organization, especially for addressing issues like lateness. It is concise and direct, making it suitable for such matters.", "marks": "1", "difficulty": "2"}, {"id": "objective>Office Practice>2025>42", "subject": "Office Practice", "year": "2025", "type": "Objective", "topic": "OFFICE EQUIPMENT : TYPES OF OFFICE EQUIPMENT", "question": "John was given some documents to stack and fasten together to avoid loss. Which of these office equipment would he use? A", "images": [], "options": {"A": "perforator", "B": "collator", "C": "jogger", "D": "stapler"}, "answer": "D", "explanation": "A stapler is the office equipment used to fasten documents together. It uses metal clips to bind sheets of paper, which is essential for keeping documents organized and preventing loss.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2025>43", "subject": "Office Practice", "year": "2025", "type": "Objective", "topic": "FILING : SYSTEMS OF FILING", "question": "One of the disadvantages of numerical system of filing is that", "images": [], "options": {"A": "it is time consuming in referring to index", "B": "misplaced files can easily be located", "C": "it does not give room for expansion", "D": "it is very difficult to file documents without geographical information"}, "answer": "A", "explanation": "One of the disadvantages of a numerical filing system is that it can be time-consuming to refer to the index to locate files, especially if the user is not familiar with the numbering system.", "marks": "1", "difficulty": "2"}, {"id": "objective>Office Practice>2025>44", "subject": "Office Practice", "year": "2025", "type": "Objective", "topic": "REPORT WRITINGS : TYPES", "question": "A weekly report given by a sales team in an organization is", "images": [], "options": {"A": "technical report", "B": "routine report", "C": "feasibility report", "D": "general report"}, "answer": "B", "explanation": "A weekly report given by a sales team is classified as a routine report. Routine reports are regularly scheduled and provide updates on ongoing activities, making them essential for tracking performance.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2025>45", "subject": "Office Practice", "year": "2025", "type": "Objective", "topic": "THE RECEPTION : DUTIES", "question": "One of the qualities a receptionist should portray is", "images": [], "options": {"A": "objectivity", "B": "thrifty", "C": "passivity", "D": "patience"}, "answer": "D", "explanation": "Patience is a crucial quality for a receptionist, as they often deal with various inquiries and situations that require a calm and composed demeanor to effectively assist clients and visitors.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2025>46", "subject": "Office Practice", "year": "2025", "type": "Objective", "topic": "OFFICE DOCUMENTS : TYPES", "question": "The document used to invite the shareholders to gather at a hotel for official discussion is", "images": [], "options": {"A": "circular", "B": "notice", "C": "letter", "D": "memo"}, "answer": "B", "explanation": "The document used to invite shareholders to gather for an official discussion is typically referred to as a 'notice'. A notice is a formal announcement that provides details about the meeting, including time, place, and agenda.", "marks": "1", "difficulty": "2"}, {"id": "objective>Office Practice>2025>47", "subject": "Office Practice", "year": "2025", "type": "Objective", "topic": "OFFICE EQUIPMENT : TYPES OF OFFICE EQUIPMENT", "question": "An equipment used for calculating and recording of sales is", "images": [], "options": {"A": "cash register", "B": "reckoner", "C": "adding machine", "D": "counting machine"}, "answer": "A", "explanation": "The equipment used for calculating and recording sales is known as a 'cash register'. A cash register is a mechanical or electronic device that records sales transactions and often includes a drawer for storing cash.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2025>48", "subject": "Office Practice", "year": "2025", "type": "Objective", "topic": "MAILS : CLASSIFICATION OF MAILS", "question": "Goods sent by the supplier's vehicle would be accompanied by", "images": [], "options": {"A": "a delivery note", "B": "a consignment note", "C": "an invoice", "D": "an advice note"}, "answer": "A", "explanation": "Goods sent by the supplier's vehicle are typically accompanied by a 'delivery note'. A delivery note is a document that accompanies a shipment of goods, detailing the items included in the delivery.", "marks": "1", "difficulty": "2"}, {"id": "objective>Office Practice>2025>49", "subject": "Office Practice", "year": "2025", "type": "Objective", "topic": "MAILS : PROCEDURES FOR HANDLING INCOMING AND OUTGOING MAILS", "question": "The proof of the receipt of a mail would be found in the", "images": [], "options": {"A": "inward register", "B": "attendance register", "C": "outward register", "D": "dispatch register"}, "answer": "A", "explanation": "The proof of receipt of mail is usually found in the 'inward register'. An inward register is a record used to log incoming mail and packages, providing evidence of receipt.", "marks": "1", "difficulty": "1"}, {"id": "objective>Office Practice>2025>50", "subject": "Office Practice", "year": "2025", "type": "Objective", "topic": "OFFICE EQUIPMENT : TYPES OF OFFICE EQUIPMENT", "question": "The secretary at OKZ Ltd received a supply of papers which would be cut in different sizes  for office use. Which of these equipment would be used?", "images": [], "options": {"A": "Guillotine", "B": "Shredder", "C": "Scanner", "D": "Perforator"}, "answer": "A", "explanation": "The equipment used to cut papers into different sizes for office use is a 'guillotine'. A guillotine is a cutting tool that allows for precise and straight cuts, making it ideal for trimming paper.", "marks": "1", "difficulty": "1"}];